export const legacyArchivePages = {
  "m2008q4.html": {
    "title": "NJSUG 2008 Fourth Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2008 Fourth Quarter Meeting</h2>\n    <p>We met 9:00am - noon on Tuesday, Dec. 9 at:</p>\n  <div class=\"c23\">\n    <p style=\"margin-left:5%\">\n      <a href=\"http://support.sas.com/training/fyi/be.html\">SAS Bedminster Training Center</a>\n      <br/>1430 US Highway 206 North\n      <br/>Suite 200\n      <br/>Bedminster, NJ 07921\n      <br/>Phone 908-470-0080\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n       <font color=\"white\">0</font>9:20-10:20<br/>\n       10:20-10:40<br/>10:40-11:40<br/>11:40- noon\n    </p>\n  </div>\n  <div class=\"c23\">\n    <p>Meeting Registration, gathering and continental breakfast<br/>\n      <a href=\"#p1\">\n        PROC SQL: Tips and Translations for Data Step Users\n      </a>(Gail Jorgensen and Susan Marcella)<br/>\n       Break<br/>\n      <a href=\"#p2\">\n        SAS Enterprise BI: the Need, the Pitch, the Implementation\n      </a>(Mike Occhipinti)<br/>\n       Random Access, Door Prizes and Closing Remarks\n  </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>PROC SQL: Tips and Translations for Data Step Users\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2008q4p1.ppt\">Presentation power point file</a>\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    PROC SQL is a powerful addition to the\n    SAS tool repertoire.  However, it can be a bit confusing to programmers more\n    accustomed to the syntax and operations of the SAS Data Step, especially when\n    attempting to make sense of various types of joins. This presentation will\n    focus on translating PROC SQL for Data Step users and will provide tips and\n    suggestions for situations in which PROC SQL can be particularly useful.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Authors</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <span style=\"color: #000066;\">Gail Jorgensen</span> is a retired applications analyst\n    currently acting as a consultant with Palisades Research, Inc.\n    Gail has worked extensively with SAS since 1976, in various capacities from\n    systems support to application design and programming. For the last 20 years,\n    she has provided database and SAS support to the Epidemiology &amp; Health Studies\n    department of ExxonMobil Biomedical Sciences, Inc. She has presented twice at SUGI.\n  </p>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <span style=\"color: #000066;\">Susan Marcella</span> is an applications analyst for the\n    Epidemiology &amp; Health Studies department of ExxonMobil Biomedical Sciences, Inc.\n    Susan has been working with SAS since 1982, starting as a teacher/consultant for\n    internal corporate staff at IBM, then as a freelance application and database\n    designer and programmer, before joining EMBSI in 2005.  Susan has an MBA in\n    Computer Applications and Information Systems from NYU Stern Graduate School of\n    Business, and has designed and taught courses in Base SAS and basic SQL queries.\n  </p>\n\n  <h2>\n    <span id=\"p2\"></span>SAS Enterprise Business Intelligence (EBI): the Need, the Pitch, the Implementation\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Healthcare data is growing\n    its size and subject area as fast as the demand for it.  Informatics at Horizon has\n    continually had to come up with new SAS technologies and business practices to\n    address the demand and delivery of health care analytics to an ever changing\n    environment.  This presentation will briefly describe our approach through SAS\n    EBI to address the future of health care reporting.  This SAS solution is adaptable\n    to any industry where there is a need for data analytics.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <span style=\"color: #000066;\">Mike Occhipinti</span> is the Director of\n    Informatics, Clinical Data Warehousing at Horizon. A SAS programmer since 1993,\n    Mike has worked for Horizon since 1990 on large scale Enterprise projects\n    including the installation of SAS on multiple platforms.\n  </p>\n  <p style=\"clear:both\"></p>\n\n \n</div>"
  },
  "m2009q1.html": {
    "title": "NJSUG 2009 First Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2009 First Quarter Meeting</h2>\n  <p>We met 9:00am - noon on Friday, March 13 at:</p>\n  <div>\n    <p>\n      <a href=\"http://maps.rutgers.edu/building.aspx?id=179\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n       <font color=\"white\">0</font>9:20-10:20<br/>\n       10:20-10:40<br/>10:40-11:40<br/>11:40- noon\n    </p>\n  </div>\n  <div class=\"c23\">\n    <p>Meeting Registration, gathering and continental breakfast<br/>\n      <a href=\"#p1\">Iterative Macro Processing with Dynamic Domains</a> (Brian Clawson)<br/>\n       Break<br/>\n      <a href=\"#p2\">Is This Macro Parameter Blank?</a> (Chang Y. Chung and John King)<br/>\n       Random Access, Door Prizes and Closing Remarks\n  </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Iterative Macro Processing with Dynamic Domains\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    I often found myself spending time creating Macro&apos;s in SAS to automate various processes,\n    and then still needing to write and execute additional code every time I went to run the\n    automated process.  The extra code was to determine what parameters needed to be passed\n    to the Macro given the current state of the data I was working with.  I realized that needing\n    to run something to determine parameters prior to running an automated process defeated the\n    purpose of automation.<br/> This paper highlights a method of using Proc SQL in SAS to query \n    a dataset to and dynamically\n    determine the parameters that should be used in a Macro, thereby allowing the entire process\n    to be scheduled, and not depend on human intervention.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Brian Clawson</span>&apos;s\n    first introduction to SAS was with MBNA America (now Bank of America)\n    in the Loss Prevention Operations group back in 2002.  Brian moved away from\n    SAS, MBNA, and the east coast to San Diego where he worked in the\n    Regional Banking Operations as a Marketing Database Analyst.  In 2005 Brian\n    moved back to the east coast with his wife to be and accepted a Risk\n    Management position with Wells Fargo Financial which brought him back to\n    regular use of SAS.  Later in 2005 Brian joined Medco Health Solutions where\n    he have been using SAS on a daily basis.\n  </p>\n\n  <h2>\n    <span id=\"p2\"></span>Is This Macro Parameter Blank?\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings09/022-2009.pdf\">SAS Global Forum 2009 paper</a>; \n    <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2009q1p2.zip\">SAS code file (zipped)</a>\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    The first thing most macros do is checking input parameters. Still, many macro users are unsure when it comes\n    to implementing the parameter checks. This is the case even with the most elementary form, namely the check of\n    the existence of a parameter value, or the &quot;Is-Blank&quot; check. We review and compare various ways to implement\n    it. We then recommend one that performs well given various input parameter values, packaged in a function-style\n    macro %ISBLANK(), which returns 1 when the parameter value is &quot;blank,&quot; and 0 otherwise.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Authors</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <span style=\"color: #000066;\">Chang Y. Chung</span> is an experienced programmer\n    specialized in statistical programming and data management. He has been using SAS for more than two decades\n    and still enjoys learning new parts of the SAS system. Chang is actively involved in the SAS community both\n    on-line and off-line.\n  </p>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <span style=\"color: #000066;\">John King</span> is a senior programmer at the Ouachita Clinical\n    Data Services. John has been using SAS for a long time and expert in SAS, data management, and statistical\n    programming. When he is not giving his expert advice on SAS programming, he enjoys engaging in conversations\n    on how to make the SAS user community better for the beginners and experts alike.\n  </p>\n  <p style=\"clear:both\"></p>\n\n</div>"
  },
  "m2009q2.html": {
    "title": "NJSUG 2009 Second Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2009 Second Quarter Meeting</h2>\n  <p>\n    NJSUG 2009 2nd Quarter meeting was in the morning (9:00am - noon) on Friday, June 26 at:\n  </p>\n  <!--\n  <div class=\"c1\">\n    <p><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/mar26th.png\" alt=\"mar 26\" /></p>\n    <p>Friday</p>\n  </div>\n  -->\n  <div>\n    <p>\n      <a href=\"http://maps.rutgers.edu/building.aspx?id=179\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p>\n      <font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n      <font color=\"white\">0</font>9:20-10:20<br/>\n      10:20-10:40<br/>10:40-11:40<br/>11:40- noon\n    </p>\n  </div>\n  <div class=\"c23\">\n    <p>\n      Meeting Registration, gathering and continental breakfast<br/>\n      <a href=\"#p1\">\n        Effective Graphics using the SG Procedures (Dan Heath)\n      </a><br/>\n      Break<br/>\n      <a href=\"#p2\">\n        Secrets of the SG Procedures/ODS Graphics Designer (Dan Heath)\n      </a><br/>\n      Random Access, Door Prizes and Closing Remarks<br/>\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Effective Graphics using the SG Procedures\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://www2.sas.com/proceedings/forum2008/255-2008.pdf\">SGF2008 Paper</a>\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    There are many types of graphics displays that you might need to create on a daily basis. In SAS ® 9.2, SAS/\n    GRAPH introduced a family of new procedures that enable you to create graphs quickly and efficiently. With very\n    little coding effort, you can create effective and attractive graphics that can be as simple as scatter plots and bar\n    charts, or as complex as multi-page classification panels.<br/><br/>\n    The new statistical graphics (SG) family of procedures includes SGPLOT, SGPANEL, and SGSCATTER. The\n    SGPLOT procedure creates single-celled graphs that can be constructed with a variety of plot and chart types. The\n    SGPANEL procedure creates paneled graphs in which the paneling is driven by classification variables. The\n    SGSCATTER procedure creates paneled scatter plots and matrices that have support for fitted lines, confidence\n    bands, and computed ellipses. These three procedures are designed with a syntax that is powerful yet concise. This\n    presentation provides examples that illustrate how you can use these procedures in your own work.\n  </p>\n\n  <h2>\n    <span id=\"p2\"></span>Secrets of the SG Procedures/ODS Graphics Designer\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings09/324-2009.pdf\">SGF2009 Paper</a>\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    The SAS/GRAPH® SG procedures provide an extensive set of plots and supporting statements to create common graphs. However, there are creative ways to combine the statements and options in these procedures that might not be obvious. This presentation will reveal some of these techniques, enabling you to create many of the specialized graphs you need in your industry.\n    These are some of the techniques that will be discussed:<br/><br/>\n    &nbsp;&nbsp;&bull; creating an area plot from a band plot<br/>\n    &nbsp;&nbsp;&bull; displaying your custom limit calculations<br/>\n    &nbsp;&nbsp;&bull; using a vector plot for event and high-low types of plots<br/>\n    &nbsp;&nbsp;&bull; using paneling options for group axis effects<br/>\n    <br/>\n    The SAS/GRAPH ODS Graphics Designer is an interactive graphical application that is used to create and design ODS graphics.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Dan Heath Interview (SGF2008)</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <object width=\"445\" height=\"364\">\n      <param name=\"movie\" value=\"http://www.youtube-nocookie.com/v/CI9LF38zNEM&amp;hl=en&amp;fs=1&amp;rel=0&amp;border=1\"></param>\n      <param name=\"allowFullScreen\" value=\"true\"></param>\n      <param name=\"allowscriptaccess\" value=\"always\"></param>\n      <embed src=\"http://www.youtube-nocookie.com/v/CI9LF38zNEM&amp;hl=en&amp;fs=1&amp;rel=0&amp;border=1\" type=\"application/x-shockwave-flash\" allowscriptaccess=\"always\" allowfullscreen=\"true\" width=\"445\" height=\"364\"></embed>\n    </object>\n  </p>\n  <p style=\"clear:both\"></p>\n</div>"
  },
  "m2009q3.php": {
    "title": "NJSUG 2009 Third Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2009 Third Quarter Meeting</h2>\n    <p>The meeting was in the morning (9:00am - noon) on Friday, September 11th at:</p>\n  <div class=\"c1\">\n    <!--\n    <p><a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/meetings.html\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/sep11th.png\" alt=\"sep 11\" /></a></p>\n    <p><a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/meetings.html\">Friday</a></p>\n    -->\n  </div>\n  <div class=\"c23\">\n    <p><br/><br/><a href=\"http://maps.rutgers.edu/building.aspx?id=179\">Rutgers Labor Education Center</a>\n       <br/>50 Labor Center Way\n       <br/>Rutgers, The State University of New Jersey\n       <br/>New Brunswick, NJ 08901</p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n       <font color=\"white\">0</font>9:20-10:20<br/>\n       10:20-10:40<br/>\n       10:40-11:40<br/>\n       11:40-noon</p>\n  </div>\n  <div class=\"c23\">\n    <p>Registration, gathering and continental breakfast<br/>\n       Data Visualization Using JMP and SAS (Valerie Hyde)<br/>\n       Break<br/>\n       Development on a Dime: Creating Your SAS Programming Environment (Michael Davis)<br/>\n       Random Access, Door Prizes and Closing Remarks</p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2><span id=\"p1\"></span>Data Visualization Using <a href=\"http://www.jmp.com/\">JMP</a> and SAS</h2>  \n\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n      <a href=\"http://www.jmp.com/software/\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/jmp.png\" border=\"none\" align=\"right\" style=\"padding: 7px\"/></a>\n      John Tukey said, &quot;The greatest value of a picture is when it forces us to notice \n      what we never expected to see.&quot;  The proposed talk focuses on using graphics to \n      grasp relationships in data and understand the meaning of statistical tests through \n      JMP&apos; visualization capabilities.  The talk also showcases some of the unique graphics in JMP:\n  </p>\n  <ul style=\"margin-left: 5%; margin-right: 5%\">\n  <li>Graph Builder which is a drag-and-drop solution to graphing</li>\n  <li>Profiler which allows people to ask &quot;what if&quot; questions for how changing different factors or inputs will affect the response</li>\n  <li>Bubble Plot which shows 5 different dimensions on one graph and allows you to change variables on the fly</li>\n  </ul>\n  <p style=\"margin-left: 5%; margin-right: 5%\"> \n      The second part of the presentation will discuss JMP&apos;s integration with SAS.  \n      This will include opening SAS data sets directly in JMP, writing and running SAS programs \n      from JMP, and running SAS stored processes from JMP. \n      The SAS results can be brought directly into JMP for further analysis.<br/><br/>\n  </p>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://www.linkedin.com/in/valeriehyde\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/vhyde.gif\" border=\"none\" align=\"left\" width=\"76px\" height=\"91px\" style=\"padding: 7px\"/>\n      <strong>Valerie Hyde</strong>\n    </a> is \n      a Systems Engineer for JMP, a division of SAS.  She is passionate about \n      data visualization and using analytics to help companies make better business decisions.  \n      Before joining SAS, Valerie worked for Accenture in the Marketing Science group and at \n      AT&amp;T Research on a project to model the effectiveness of viral marketing on a direct \n      mail campaign.  She has also performed econometric modeling for the US Justice Department&apos;s \n      Antitrust Division, the US Census Bureau, and MiCRA Inc., a boutique consulting company.<br/><br/>\n \n      Valerie earned a PhD in applied mathematics and statistics from the University of Maryland.  \n      Her research, which has been published in The American Statistician and Computational Statistics \n      and Data Analysis, focused on mining online auction data for patterns in the price process.  \n      She also has a bachelor&apos;s degree in mathematics and economics from Binghamton University.<br/> \n  </p> \n\n  <h2><span id=\"p2\"></span>Development on a Dime: Creating Your SAS Programming Environment</h2>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Download: <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2009q3p2.zip\">Presentation Slides and UserDefineLang.xml</a> (zipped). See the Readme.txt\n    file for the installation instruction fot the xml file.\n  </p>\n  <p style=\"margin-left: 5%; margin-right: 5%\"> \n      When the author joined HMS, the use of SAS software was new to his organization.  Given a preference for \n      software development tools that were inexpensive and open-source, the author assembled a SAS development \n      environment to make program creation and data analysis easier and faster.  Key elements of this environment include:\n  </p>\n  <ul style=\"margin-left: 5%; margin-right: 5%\">\n  <li>Notepad++ Editor, configured to color-code key SAS words</li>\n  <li>library of frequently used program templates, routines and lookup tables</li>\n  <li>departmental Autoexec.sas program and Autocall macro library</li>\n  </ul>\n  <p style=\"margin-left: 5%; margin-right: 5%\">  \n      Batch processing is the author&apos;s favorite mode of executing substantial SAS programs so he modified \n      his MS Windows desktop mode so the development environment was adjusted to make it easier to create new SAS program.<br/><br/>\n      Recently, SAS was also licensed and installed on a Linux server.  The author is currently at work to update \n      the development environment so that programs can be run under Windows or Linux without alteration.<br/><br/>\n  </p>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/mdavis.gif\" border=\"none\" align=\"left\" width=\"76px\" height=\"91px\" style=\"padding: 7px\"/>\n      <strong>Michael Davis</strong> is a \n      Senior SAS Analyst for Health Market Science in King of Prussia.  \n      He undertakes programming and statistical analysis in support of product development.  \n      He previously worked for Aetna, Blue Cross &amp; Blue Shield of Connecticut and the \n      Connecticut Hospital Association. Michael has been a SAS user since 1985 and previously \n      specialized in developing decision support, data warehousing and web-based systems with \n      SAS software.  He has frequently presented papers at SUGI/SGF, NESUG, and local SAS user groups.  \n      Michael holds a Masters in Health Administration from Duke University. <br/><br/>\n   </p>   \n</div>"
  },
  "m2009q4.php": {
    "title": "NJSUG 2009 Fourth Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2009 Fourth Quarter Meeting</h2>\n    <p>The meeting was in the morning (9:00am - noon) on Friday, December 11th at:</p>\n  <div class=\"c23\">\n    <p style=\"margin-left:5%\">\n       <a href=\"http://support.sas.com/training/fyi/be.html\">SAS Bedminster Training Center</a>\n       <br/>1430 US Highway 206 North\n       <br/>Suite 200\n       <br/>Bedminster, NJ 07921\n       <br/>Phone 908-470-0080</p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n       <font color=\"white\">0</font>9:20-10:20<br/>\n       10:20-10:40<br/>\n       10:40-11:40<br/>\n       11:40-noon<br/>\n    </p>\n  </div>\n  <div class=\"c23\">\n    <p>Registration, gathering and continental breakfast<br/>\n       Let Your Data Power Your DATA Step (Howard Schreier)<br/>\n       Break<br/>\n       Using PROC RANK and PROC UNIVARIATE to Rank or Decile Variables (Jonas Bilenas)<br/>\n       Random Access, Door Prizes and Closing Remarks\n  </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Let Your Data Power Your DATA Step: Making Effective Use of the SET,\n    MERGE, UPDATE, and MODIFY Statements\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Downloads</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Download <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2009q4p1.zip\">paper(pdf, zipped)</a> and view the \n    <a href=\"http://www.howles.com/saspapers/251-30/251-30_files/v3_document.htm\">on-line presentation</a>. Or visit Howards'\n       web site at <a href=\"http://www.howles.com/\">http://www.howles.com</a>.\n  </p>\n  \n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    The \"plain vanilla\" SET statement is ubiquitous in SAS(r) programming.\n    It feeds the contents of a data set to a DATA step. This usage only\n    scratches the surface of the capabilities of the SET statement and its\n    siblings (MERGE, UPDATE, and MODIFY). Data sets typically are more than\n    collections of individual values; they also incorporate information in\n    the form of structure and organization. The SET, MERGE, UPDATE, and\n    MODIFY statements are versatile tools that can use such information to\n    combine and refine data. This tutorial will explain and illustrate the\n    basic capabilities of each of these statements and will compare their\n    advantages and disadvantages in different programming situations.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author\n    <a href=\"http://support.sas.com/publishing/bbu/companion_site/60500.html\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/procsql.gif\" style=\"float:right; padding:5px;\" border=\"none\" width=\"86\" height=\"112\"/>\n    </a>\n  </h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n\n    <a href=\"http://www.howles.com/saspapers/\">Howard Schreier</a> \n    is an independent consultant based in Arlington,\n    Virginia. He has used SAS software since 1981 and has presented papers\n    at numerous NESUG, SESUG, and SUGI conferences. Since 1989, he has made\n    nearly 8,000 postings to SAS-L, and in 2004 he entered the SAS-L Hall of\n    Fame.\n    <br/>\n  </p>\n\n  <h2>\n    <span id=\"p2\"></span>Using PROC RANK and PROC UNIVARIATE to Rank or Decile Variables\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Downloads</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Download <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2009q4p2.zip\">paper(pdf, zipped)</a> or visit Jonas'\n    web site at <a href=\"http://www.jonasbilenas.com/sas_stuff.html\">http://www.jonasbilenas.com/sas_stuff.html</a>.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    In direct marketing applications prospects are often ranked by scores that\n    predict response, risk and/or profitability.  Justification is to evaluate\n    lifts in performance by soliciting the most profitable individuals as defined\n    by score ranking.  Many programmers write complicated code using PROC SORT,\n    MACRO calls, and DATA STEPS to rank or decile these scores.  These programs\n    often don't handle score ties which can result when 2 or more prospects with\n    the same score end up in 2 or more ranks.  We will show how using PROC RANK\n    will provide a quick and simple way to rank or decile individuals that will\n    handle ties with the PROC RANK TIES option.  We will look at the syntax of\n    PROC RANK with a number of examples and applications.  Since PROC RANK does\n    not have a WEIGHT statement to handle weighted samples we will show how to\n    handle weights using PROC UNIVARIATE and PROC FORMAT to perform a weighted\n    ranking.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author\n    <a href=\"http://www.sas.com/apps/pubscat/bookdetails.jsp?pc=59498\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/procformat.gif\" style=\"float:right;padding:5px;\" border=\"none\" width=\"86\" height=\"112\"/>\n    </a>  \n  </h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://www.jonasbilenas.com/sas_stuff.html\">Jonas Bilenas</a> is VP of Decision \n    Science at JP Morgan Chase Bank in the area\n    of Consumer Acquisitions and Targeting.  Jonas has been using SAS since 1986\n    in areas of credit modeling, reporting, experimental design, simulation and\n    optimization.  He is the author of the SAS Press Book, \"The Power of PROC\n    FORMAT\", and is currently working on a new book with the tentative title of\n    \"SAS Applications in the Credit Industry\".\n  </p>\n\n</div>\n\n<div class=\"container\">\n  <h2>Annual SAS Book Sale</h2>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    This is the NJSUG Annual SAS Book Sale meeting. All attendees will get\n    a 20% discount certificate for SAS publishing books. Visit SAS Publishing\n    <a href=\"http://support.sas.com/publishing/index.html\">bookstore</a> and see wonderful\n    new books and old favorites.\n    <br/><br/>\n  </p>\n</div>"
  },
  "m2010q1.php": {
    "title": "NJSUG 2010 First Quarter Meeting and Special Afternoon Training",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2010 First Quarter Meeting and Special Afternoon Training</h2>\n    <p>The meeting was in the morning (9:00am - noon) followed by \n       Special Training Session in the afternoon (1:00 - 4:45pm) on Friday, December 11th at:</p>\n  <!--\n  <div class=\"c1\">\n    <p><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/mar26th.png\" alt=\"mar 26\" /></p>\n    <p>Friday</p>\n  </div>\n  -->\n  <div>\n    <p>\n      <a href=\"http://maps.rutgers.edu/building.aspx?id=179\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <div class=\"c1\">\n    <p><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20<br/>\n       <font color=\"white\">0</font>9:20-10:20<br/>\n       10:20-10:40<br/>10:40-11:40<br/>11:40- noon<br/>1:00-4:45pm\n    </p>\n  </div>\n  <div class=\"c23\">\n    <p>Meeting Registration, gathering and continental breakfast<br/>\n       <a href=\"#p1\">Revolutionary BI</a> (Charles Kincaid)<br/>\n       Break<br/>\n       <a href=\"#p2\">SAS Formats and Informats</a> (Ron Cody)<br/>\n       Random Access, Door Prizes and Closing Remarks<br/>\n       <a href=\"#s1\">Special Afternoon Training</a> (Ron Cody)\n  </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Revolutionary BI: A Vision for Business Intelligence\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    See or download the <a href=\"http://corp.comsys.com/docs/analytics/WP_BA_Revolutionary_BI_032709.pdf\">paper</a>. Check out other excellent COMSYS <a href=\"http://corp.comsys.com/analytics/whitepapers.html\">white papers</a>, as well!\n  </p>  \n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    We generate and use Business Intelligence Reports in much the same way we\n    used paper reports. However, like the Reese's Peanut Butter Cup we get\n    even better results when we combine our information and analytics with\n    new methods of creating and distributing them.<br/><br/>\n    This session is intended to get people to think in a new way about business\n    intelligence reporting and business analytics that increases the\n    probability of BI success. It will reference many web 2.0 technologies\n    such as mash- ups, RSS, etc., and show how you can incorporate popular\n    apps like Google, Yahoo, wiki, etc. into your SAS applications.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/charlesKincaid.png\" style=\"float:left; padding:0 5px 5px 0;\" border=\"none\" width=\"76\" height=\"91\"/>\n    Charles Kincaid has been with COMSYS since March of 1999, he runs three SAS Centers\n    of Excellence for COMSYS: Somerset, NJ; Kalamazoo, MI; and San Francisco, CA.\n    As Engagement Director, he is responsible for the quality of all of the work\n    that is done in and through these Centers.<br/><br/>\n    Prior to joining COMSYS he was a Statistician with Kellogg Company,\n    a Statistical Consultant and a full time Lecturer with Dept of Statistics\n    for the University of Florida.<br/><br/>\n    He holds a PhD degree in Statistics from University of Florida as well as a MS\n    in Statistics and a BS in Computer Sciences out of Kansas State University.\n    <br/>\n  </p>\n\n  <h2>\n    <span id=\"p2\"></span>Using Advanced Features of User-defined Formats and Informats\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Download</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    SAS Global Forum 2010 paper is linked\n    <a href=\"http://support.sas.com/resources/papers/proceedings10/022-2010.pdf\">here</a>.\n    You've seen this presentation first at NJSUG before it is presented at SGF 2010!\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Abstract</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    Formats can do more than just make your output more readable. This paper discusses\n    several of the more advanced features of formats, such as using formats to create\n    new variables, using informats to filter data errors,\n    reading combinations of character and numeric values in one step (using enhanced\n    numeric informats), using formats for table look-up, embedding formats within\n    other formats, multi-label formats, control datasets, and creating format\n    names on the fly in a DATA Step to allow multi-way table lookups.\n  </p>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Author</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    <a href=\"http://support.sas.com/publishing/authors/cody.html\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/ronCody76x90.png\" style=\"float:left;padding:0 5px 5px 0;\" border=\"none\" width=\"76\" height=\"90\"/>\n    </a>\n    Ron Cody, Ed.D., is a retired professor from the Robert Wood Johnson Medical\n    School who now works as a private consultant and a national instructor for\n    SAS Institute Inc. A SAS user since 1977, Ron's extensive knowledge and\n    innovative style have made him a popular presenter at local, regional, and\n    national SAS conferences. He has authored or co-authored numerous SAS books.\n  </p>\n  <p style=\"clear:both\"></p>\n\n  <h2>\n    <span id=\"s1\"></span>An Introduction to Data Cleaning with Ron Cody\n    -- SPECIAL AFTERNOON TRAINING SESSION\n  </h2>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Overview</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    This half-day workshop (1:00pm to 4:45pm) explores ways to look for data errors\n    using both DATA step programming and Base SAS procedures.  Functions\n    such as VERIFY and several of the new SAS 9 character functions make\n    SAS especially well suited to this task.  Topics to be discussed include:\n  </p>\n  <ul style=\"margin-left: 5%; margin-right: 5%; list-style-position: inside\">\n    <li>Checking values of character variables</li>\n    <li>Detecting numeric outliers</li>\n    <li>Checking for duplicate observations</li>\n    <li>Correcting data</li>\n    <li>Creating integrity constraints and audit trails</li>\n  </ul>\n\n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Instructor</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    \n    <a href=\"http://support.sas.com/publishing/bbu/podcasts/sgf09/cody_ceranowski.mp3\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/podcast.png\" style=\"float:left; padding: 0 10px 5px 5px;\" border=\"none\" width=\"38\" height=\"38\"/>\n    </a>\n    <a href=\"http://support.sas.com/publishing/authors/cody.html\">\n      Ron Cody.\n    </a>\n    <a href=\"http://support.sas.com/publishing/bbu/podcasts/sgf09/cody_ceranowski.mp3\">Listen</a> to Ron's interview at\n    the SGF2009 discussing the popularity of his recent book,\n    <a href=\"http://www.sas.com/apps/pubscat/bookdetails.jsp?pc=60864\">Learning SAS by Example: A Programmer's Guide.</a> Click on the podcase icon on \n           the left to find out what Ron does when he is not teaching SAS! (mp3, 8:24)\n    <br/>\n  </p>\n  <div style=\"clear:both\"/>\n  \n  <h3 style=\"margin-left: 5%; margin-right: 5%\">Cost and Registration</h3>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n      <!--\n      <a target=\"_blank\" href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/registration2010q1.pdf\" style=\"float:left;padding:0 24px 5px 24px;\">\n        <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/formSmall.jpg\" alt=\"registration form\" />\n      </a>\n      -->\n    This afternoon session is at an additional cost of $125 per person, including \n    a copy of course materials.\n    It is open to members as well as to non-members. Registration must be done in advance to\n    ensure an adequate supply of training materials. Checks should be made payable\n    to: NJ SAS Users Group. To register for the class, call NJSUG Treasurer Ted Vittas at\n    (973) 753-6311 or email us at <a href=\"https://web.archive.org/web/20240419174211/mailto:nj.sas.users.group@gmail.com\">nj.sas.users.group@gmail.com</a>.\n  </p>\n  <p style=\"font-size:90%;margin-left: 5%; margin-right: 5%\">\n    Payment must be arranged in advance.\n    The NJSUG serves the right to cancel the class at any time.\n    In this case, only course registration fees will be refunded in full.\n  </p>    \n</div>"
  },
  "m2010q2.php": {
    "title": "NJSUG 2010 Second Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2010 Second Quarter Meeting</h2>\n    <p>The meeting was in the morning (9:00am - noon) on Friday, May 7th at:</p>\n  <div class=\"c1\">\n    <!-- \n    <p class=\"notopmargin\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/may7th.png\" alt=\"may 7\" /></p>\n    <p class=\"notopmargin\">Friday</p>\n    -->\n  </div>\n  <div class=\"c23\">\n    <p>\n      <br/><a href=\"http://maps.rutgers.edu/building.aspx?id=179\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20</td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td></tr>\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:20-10:20</td>\n      <td class=\"agendatext\">Tiptoe Through the Templates (Cynthia Zender)</td></tr>\n    <tr>\n      <td class=\"agendatime\">10:20-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:40-11:40</td>\n      <td class=\"agendatext\">The &quot;Hottest&quot; SAS Skills: A Roundtable Discussion</td></tr>\n    <tr>\n      <td class=\"agendatime\">11:40-noon</td>\n      <td class=\"agendatext\">Closing Remarks and Door Prize Drawing</td></tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Tiptoe Through the Templates\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    Download Cynthia's <a href=\"http://support.sas.com/resources/papers/proceedings09/227-2009.pdf\">SAS Global Forum 2009 paper</a>. Check out her\n    <a href=\"http://support.sas.com/publishing/authors/zender.html\">SAS Publishing Author page</a>, and visit support.sas.com's\n    <a href=\"http://support.sas.com/rnd/base/ods/index.html\">ODS anchor point</a>\n    with lots of useful information!\n  </p>\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    Are you confused about the difference between style templates, table templates,\n    tagset templates, and graph\n    templates? Do you wonder how they're all used with ODS?\n  </p>\n  <p class=\"narrower\">\n    This paper provides an overview of all the different template types and\n    how they're used with the Output Delivery\n    System. From style and table templates, that first appeared with\n    SAS 7 to the newest graph templates that appeared\n    with SAS 9.2, this paper will provide an overview and several\n    concrete examples for each template type. Along the\n    way, we'll also discuss the template garden (SASHELP.TMPLMST) where all\n    the templates live, how to transplant\n    your templates to a different garden, how to come up with your own new\n    variety of templates (PROC TEMPLATE),\n    and how to find your way to the new template garden (ODS PATH). New\n    features of PROC TEMPLATE syntax (such\n    as the IMPORT statement) will be highlighted.\n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Cynthia Zender has been with SAS since 1996 as an instructor and course\n    developer. She currently serves as the Curriculum Manager for Report\n    Writing and Output Delivery System education. She has over 25 years of\n    experience programming and reporting with SAS in a number of different\n    industries such as education, public utility, and telecom.\n  </p>\n  <p class=\"narrower\">\n    Cynthia is a frequent speaker at SAS Global Forum and regional SAS users\n    groups. She recently finished two graph-related courses and is the co-author\n    of <a href=\"http://www.sas.com/apps/pubscat/bookdetails.jsp?pc=61686\">Output Delivery System: The Basics and Beyond</a>.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>Roundtable Discussion: The \"Hottest\" SAS Skills\n  </h2>\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    What are the most sought after SAS skills in New Jersey?\n    You will hear different perspectives on what employers are looking for\n    in terms of skills and experiences in the current competitive market\n    for SAS related jobs.\n  </p>\n\n  <h3 class=\"narrower\">Moderator and Discussants</h3>\n  <p class=\"narrower\">\n    Moderator: Roberto Lopez (NJSUG)<br/>\n    Discussants: Matt Aston (Smith Hanley); Gourish Hosangady (Inforeem);\n    Beilei Xu (Merck); and Cynthia Zender (SAS)  \n  </p>\n\n  <p style=\"clear:both\"></p>\n</div>"
  },
  "m2010q3.php": {
    "title": "NJSUG 2010 Third Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2010 Third Quarter Meeting</h2>\n    <p>The meeting was in the morning (9:00am - noon) on Friday, Oct 1st at:</p>\n  <div class=\"c1\">\n    <!-- \n    <p class=\"notopmargin\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/may7th.png\" alt=\"may 7\" /></p>\n    <p class=\"notopmargin\">Friday</p>\n    -->\n  </div>\n  <div class=\"c23\">\n    <p>\n      <br/><a href=\"http://maps.rutgers.edu/building.aspx?id=179\" target=\"_map\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20</td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td></tr>\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:20-10:20</td>\n      <td class=\"agendatext\">Condensed and Sparse Indexes for Sorted SAS Datasets (Mark Keintz)</td></tr>\n    <tr>\n      <td class=\"agendatime\">10:20-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:40-11:40</td>\n      <td class=\"agendatext\">What&apos;s New with JMP9 (Valerie Hyde)</td></tr>\n    <tr>\n      <td class=\"agendatime\">11:40-noon</td>\n      <td class=\"agendatext\">Closing Remarks and Door Prize Drawing</td></tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Condensed and Sparse Indexes for Sorted SAS Datasets\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">Power point <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2010q3p1.zip\">presentation file</a></p>\n  \n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    The standard SAS index normally can speed up data retrieval of subsets, but can\n    be suboptimal for datasets sorted on the index variable.  For large sorted groups\n    the normal index wastes disk space by creating a \"pointer\" to every record in the\n    group.  This paper demonstrates a condensed index with pointers only to the first\n    and last record in each group.  Dramatic reductions in elapsed time, input/output,\n    and disk space are realized.\n  </p>\n  <p class=\"narrower\">\n    The paper will also show results for a \"sparse\" index for sorted data in which groups \n    are relatively small but the index range is large (e.g. every second over a span of days).  \n    When retrieving a subset of cases between a pair of values of the sort variable, \n    an index that points to only a few selected records can also save disk space and elapsed time.\n  </p>\n  \n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Mark Keintz is a Senior Data Analyst at the Wharton Research Data Services group.  \n    His current interests are in developing and supporting financial research applications, \n    and managing large datasets.  Mark has been using SAS since it was documented in one book.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>What's New with JMP&reg;&nbsp;9\n  </h2>\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    JMP&reg;&nbsp;9, to be released on October 12, has many new and exciting features.  One enhancement\n    is the new mapping capability, such as being able to put a map behind your data in the graph\n    builder and the bubble plot.  This enables data overlays to any kind of geospatial data.\n    Data mining techniques have also been stepped up.  It will be even easier to \"train,\n    validate, and test\" you data, resulting in more robust models that produce better predictions.\n    The partition platform, which is JMP's decision tree, now also includes bootstrap forests and boosted trees.\n  </p>\n  <p class=\"narrower\">\n    JMP is fully integrated with SAS.  It will be shown how to run SAS code from within JMP, \n    as well and SAS and JMP code together. This integration enables the scalability of SAS to \n    be harnessed to a high graphical client via JMP.  This is truly the best of both worlds.\n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Valerie Hyde is a Systems Engineer for JMP, a division of SAS. She is passionate about data \n    visualization and using analytics to help companies make better business decisions. \n    Before joining SAS, Valerie worked for Accenture in the Marketing Science group and at AT&T; \n    Research on a project to model the effectiveness of viral marketing on a direct mail campaign. \n    She has also performed econometric modeling for the US Justice Department's Antitrust \n    Division, the US Census Bureau, and MiCRA Inc., a boutique consulting company.\n  </p>\n  <p class=\"narrower\">\n    Valerie earned a PhD in applied mathematics and statistics from the University of Maryland. \n    Her research, which has been published in The American Statistician and Computational \n    Statistics and Data Analysis, focused on mining online auction data for patterns in the \n    price process. She also has a bachelor's degree in mathematics and economics from \n    Binghamton University.\n  </p>\n\n  <p style=\"clear:both\"></p>\n</div>"
  },
  "m2010q4.php": {
    "title": "NJSUG 2010 Fourth Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2010 Fourth Quarter Meeting</h2>\n    <p>The meeting was in the morning (9:00am - noon) on Friday, Dec 10th at:</p>\n  <div class=\"c1\">\n    <!-- \n    <p class=\"notopmargin\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/may7th.png\" alt=\"may 7\" /></p>\n    <p class=\"notopmargin\">Friday</p>\n    -->\n  </div>\n  <div class=\"c23\">\n    <p>\n      <a href=\"http://support.sas.com/training/fyi/be.html\">SAS Bedminster Training Center</a>\n      <br/>1430 US Highway 206 North\n      <br/>Suite 200\n      <br/>Bedminster, NJ 07921\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20</td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td></tr>\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:20-10:20</td>\n      <td class=\"agendatext\">Interactive and Efficient Macro Programming with Prompts in SAS Enterprise Guide (Kenneth Sucher)</td></tr>\n    <tr>\n      <td class=\"agendatime\">10:20-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:40-11:40</td>\n      <td class=\"agendatext\">Handling XML Documents with SAS (Lex Jansen)</td></tr>\n    <tr>\n      <td class=\"agendatime\">11:40-noon</td>\n      <td class=\"agendatext\">Closing Remarks and Door Prize Drawing</td></tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>Interactive and Efficient Macro Programming with Prompts in SAS Enterprise Guide\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings10/036-2010.pdf\">Paper(pdf)</a> \n    presented at SAS Global Forum 2010</p> \n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    SAS Enterprise Guide is the front-end Windows client that provides a point-and-click\n    interface to access and analyze your data in SAS. Longtime users of SAS, especially those who already take\n    advantage of macro processing, might shy away from SAS Enterprise Guide, seeing it as a tool for novice users or\n    useful only for creating a stored process. This paper focuses on macro processing use (called \"prompts\")\n    inside the SAS Enterprise Guide environment. I intend to demonstrate some advanced techniques that are not\n    only very practical, but only possible in the SAS Enterprise Guide environment.\n  </p>\n  <p class=\"narrower\">\n    Topics covered include: creating and\n    using prompts in tasks and queries, multiple value and range prompts,\n    running tasks conditionally, and adding runtime\n    prompts to a user‟s own code. This paper is especially useful for current SAS programmers who are interested\n    in increasing the functionality of their macro programming skills, as well as non-macro users looking for a less\n    programmatic introduction to macro processing within the SAS Enterprise Guide environment.\n  </p>\n  \n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Kenneth Sucher is an advanced SAS certified instructor for SAS Education. He received his master's degree \n    in sociology from Florida State University.  Kenneth used SAS during grad school and he honed his \n    SAS skills while working as a statistician for the Census Bureau and later as a demographer for the \n    Urban Institute.  Since coming to SAS 5 years ago, he has become an Enterprise Guide expert.  \n    Kenneth teaches and works on course development for Enterprise Guide as well as SAS programming courses \n    including macro and SQL processing.  Kenneth currently lives in Washington, DC.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>Handling XML Documents with SAS\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2010q4p2.pdf\">Presentation(pdf)</a>. Also check out Lex's award winning \n    SAS conference papers at his site, <a href=\"http://www.lexjansen.com/\">http://www.lexjansen.com/</a>\n  </p>\n\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    Reading and writing XML Documents in SAS becomes an essential skill for SAS users as an increasing\n    amount of information is exchanged as XML Documents. Through presentation and demonstration,\n    I will go over some basics about XML documents, XML library engine, and XML Mapper. I will also\n    share some lessons learned from handling XML documents using SAS and showcase some of the advanced \n    handlings of more complicated XML related technology in the context of CDIS SDTM data submission.\n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Lex Jansen is a senior consultant in the Clinical Data Strategies section of Octagon Research\n    Solutions, Inc. Lex has nearly 20 years of professional experience in the pharmaceutical industry.\n    He was the senior director, Clinical Information Systems at TAKE Solutions where he consulted with\n    clients to help them with their CDISC SDTM implementations and designed and developed a SAS toolset\n    to support SDTM implementations. He also spent sixteen years at Organon in global biometrics where\n    he was responsible for the global biometrics SAS infrastructure and served as technical lead for the\n    CDISC Implementation Team, project lead and technical lead for Organon's CDISC SDTM Late Stage\n    Conversion Project and a core member of the SDTM-based data warehouse project. Mr. Jansen has\n    experience leading SDTM implementation projects and infrastructure design projects. He is a member\n    of the CDISC XML Technologies team and a member of the editorial board of the Pharmaceutical\n    Programming journal. Mr. Jansen is a frequent presenter at SAS User Group conferences. His web site\n    (<a href=\"http://lexjansen.com/\">http://www.lexjansen.com/</a>) is a well-known destination for SAS\n    users as it features over 11,000 links to the most of the global and regional SAS conference papers.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>Annual SAS Book Sale</h2>\n  <p style=\"margin-left: 5%; margin-right: 5%\">\n    This is the NJSUG Annual SAS Book Sale meeting. All attendees will get\n    a 20% discount certificate for SAS publishing books. Visit SAS Publishing\n    <a href=\"http://support.sas.com/publishing/index.html\">bookstore</a> and see wonderful\n    new books and old favorites.\n    <br/><br/>\n  </p>\n  <p style=\"clear:both\"></p>\n</div>"
  },
  "m2011q1.php": {
    "title": "NJSUG 2011 First Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2011 First Quarter Meeting</h2>\n  <p>The meeting was in the morning (9:00am - noon) on Friday, Mar 25th at:</p>\n  <div class=\"c1\">\n  </div>\n  <div class=\"c23\">\n    <p>\n      <a href=\"http://rumaps.rutgers.edu/?q=bnum:6109\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>  \n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20</td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td></tr>\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:20-10:20</td>\n      <td class=\"agendatext\">Presentation: Let's Make Some Tag Clouds (Chang Chung and John King)</td></tr>\n    <tr>\n      <td class=\"agendatime\">10:20-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:40-10:45</td>\n      <td class=\"agendatext\">Random Access (announcements)</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:45-11:45</td>\n      <td class=\"agendatext\">Presentation: It's All About Variation (Blair Christian)</td></tr>\n    <tr>\n      <td class=\"agendatime\">11:45-noon</td>\n      <td class=\"agendatext\">Door Prize Drawings</td></tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p1\"></span>What Were We Talking about at Those SAS Conferences, or Let's Make Some Tag Clouds\n  </h2>\n  \n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings11/253-2011.pdf\">Paper(pdf)</a> \n    to be presented at SGF2011</p> \n  \n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    A tag cloud is a bunch of tags or words displayed nicely. More popular or important words \n    are highlighted using different colors or font sizes. Popularized by Flickr and other \n    Web 2.0 websites, tag clouds can be informative and useful. This presentation will discuss \n    making tag clouds using nothing but Base SAS. The keywords come from the titles of all \n    papers presented at two international SAS conferences: the 25th SAS Users Group International \n    Conference in 2000 (SUGI 25) and SAS Global Forum 2010.\n  </p>\n  \n  <h3 class=\"narrower\">Authors</h3>\n  <p class=\"narrower\">\n  Chang Y. Chung is an experienced statistical programmer specialized in SAS programming and \n  data management. He authored several conference papers and presented them at NESUG, \n  PharmaSUG, and SGF. He is active in the user communities local and global.\n  </p>\n  <p class=\"narrower\">\n  John King is a senior programmer at the Ouachita Clinical Data Services. John has been using \n  SAS for a long time and expert in SAS, data management, and statistical programming. When \n  he is not giving his expert advice on SAS programming, he enjoys engaging in conversations \n  on how to make the SAS user community better for the beginners and experts alike.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>It's All About Variation: Improving Your Business Process with Statistical Thinking\n  </h2>\n  \n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings10/294-2010.pdf\">Paper(pdf)</a>\n    presented at SGF 2010\n  </p>\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    Do you need to detect unusual variation in your data? Have you ever wondered whether control\n    charts might work for business activity monitoring? Christian will explain how concepts and\n    methods of statistical process monitoring, traditionally used in manufacturing, are finding\n    fresh and valuable applications in business environments ranging from financial services to\n    health care.\n  </p>\n  <p class=\"narrower\">\n    The starting point is a set of problems encountered by statisticians, analysts and managers in \n    these settings. For each vignette, the key to the solution is a statistical understanding of \n    the variation in the business process. Approaches range from control chart methods in SAS/QC&reg; \n    software to statistical modeling techniques in SAS/STAT&reg; software. Common to all these \n    methods are graphical displays for visualizing the variation, which is critical for explaining \n    results to clients and management. Graphical displays can be created with ODS Statistical \n    Graphics in SAS 9.2. Also, you'll get example programs to get you started.\n  </p>\n\n  <h3 class=\"narrower\">Presenter</h3>\n  <p class=\"narrower\">\n    Blair Christian is a new research statistician developer at SAS.  He focuses on the SAS/QC \n    product, and is busy developing functionality for non-traditional uses of process control in \n    industries other than manufacturing, such as banking, insurance and healthcare.  He received \n    a doctorate in statistics from Rice University with a focus in methods for genetics and \n    genomics.  He has a wide range of professional experience in computational statistics including \n    positions in a genetics group, a revenue optimization firm, and in the spatiotemporal \n    modeling of air pollution.\n  </p>\n</div>\n\n<p style=\"clear:both\"></p>"
  },
  "m2011q2.php": {
    "title": "NJSUG 2011 Summer Meeting",
    "content": "<div class=\"container\">\n  <h2>NJSUG 2011 Summer Meeting</h2>\n  <p>The meeting was in the morning (9:00am - noon) on Friday, July 8th at:</p>\n  <div class=\"c123\">\n    <p>\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/july8th.png\" alt=\"july8th\" border=\"none\" style=\"padding-right: 6px\" align=\"left\" valign=\"top\"/>\n      <a href=\"http://rumaps.rutgers.edu/?q=bnum:6109\">Rutgers Labor Education Center</a>\n      <br/>50 Labor Center Way\n      <br/>Rutgers, The State University of New Jersey\n      <br/>New Brunswick, NJ 08901\n    </p>\n  </div>  \n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20</td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td></tr>\n    <tr>\n      <td class=\"agendatime\"><font color=\"white\">0</font>9:20-10:30</td>\n      <td class=\"agendatext\">Presentation: PROC FORMAT:The Basics and Beyond (Andrew Karp)</td></tr>\n    <tr>\n      <td class=\"agendatime\">10:30-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:40-10:45</td>\n      <td class=\"agendatext\">Random Access (announcements)</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:45-11:55</td>\n      <td class=\"agendatext\">Presentation: PROC MEANS:Basics and Beyond (Andrew Karp)</td></tr>\n    <tr>\n      <td class=\"agendatime\">11:55-noon</td>\n      <td class=\"agendatext\">Door Prize Drawings</td></tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n\n  <h2>Andrew Karp</h2>\n  \n  <p class=\"narrower\"><img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/andrew_karp.jpg\" alt=\"andrew_karp\" border=\"none\" style=\"padding-right: 12px\" align=\"left\" valign=\"top\"/>\n  This meeting offers two in-depth presentations by internationally recognized SAS\n  Software expert Andrew Karp of Sierra Information Services. These Two 70-minute talks focus on core\n  SAS BASE toos you can apply right away to simplify your report, data management, and analysis tasks.</p>\n\n  <p class=\"narrower\">Andrew Karp grew up in Central New Jersey and first learned about SAS Software \n  while in graduate school at The George Washington University in Washington, DC.  He is now in his \n  29th year of using SAS Software, his 23rd year of training others how to use it, and his 17th year \n  as an independent SAS consultant.  Since starting his firm, Sierra Information Services, in 1994 \n  he has flown over 1.3 million air miles to participate in events for SAS users in 11 countries, \n  has been an invited speaker at 16 consecutive SAS Global Forum meetings, and has served on the \n  review teams for eight books published by SAS Press, an imprint of SAS Institute&apos;s Publications \n  Division.  Andrew now makes his home in the California Wine Country.  He is an avid amateur photographer \n  who is hard at work learning how to use his new Nikon D90 Digital SLR camera.\n  </p>\n  \n  \n  <h2>\n    <span id=\"p1\"></span>PROC FORMAT: The Basics and Beyond\n  </h2>\n  \n  <!--\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings11/253-2011.pdf\">Paper(pdf)</a> \n    to be presented at SGF2011</p> \n  -->  \n  \n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    This 70-minute presentation starts with the fundamentals of Formats and their core role\n    in the SAS System to display data values without having to change the values themselves.\n    We will explore the use of SAS-supplied formats and how to create customized formats using\n    PROC FORMAT.  The presentation will then move on to more advanced/powerful aspects of the\n    SAS Format facility, including using Formats to \"bin\" or \"bucket\" values of variables,\n    the power of the MULTILABEL Format facility, creating \"Formats within a Format,\" using\n    Input Control Data Sets to assign Format labels without tedious coding, creating Formats\n    to group/display data by fiscal years vs. calendar years, exploring the contents of Format\n    Libraries with the FMTLIB option, and the how to use the PRELOADFMT option in the REPORT\n    and TABULATE procedures.\n  </p>\n  <p class=\"narrower\">\n    Intended Audience:  This talk is appropriate for users of SAS&apos; syntax-based tools at all \n    experience levels.  The topics/concepts presented assume the attendee is already familiar \n    with core SAS programming concepts such as data set, observation, variable, label, \n    procedure, and data step.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>PROC MEANS: The Basics and Beyond</h2>\n  \n  <!--\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings10/294-2010.pdf\">Paper(pdf)</a>\n    presented at SGF 2010\n  </p>\n  -->\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    PROC MEANS offers SAS users a wide range of powerful tools to manage, report and analyze data.\n    By attending this 70-minute talk you will learn about the core functionalities of this BASE\n    SAS procedure, and then see some of the powerful \"beyond the basics\" tools you can use to\n    rapidly aggregate, report and manage your data.  Among the topics covered are:  working with\n    default PROC MEANS output, controlling procedure-generated display in your Output Window,\n    selecting statistics to be computed, saving results in a SAS data set, creating multiple summary\n    output SAS data sets with the CHARTYPE option, using the ORDER= option to control how your\n    results are either displayed in the output window or stored in a new data set, the role of\n    Multilabel Formats in PROC MEANS, the powerful AUTONAME and AUTOLABEL options to control how\n    variable names and labels are assigned when PROC MEANS creates a SAS data set, and how to reduce\n    processing time with the TYPES and WAYS statements.\n  </p>\n  <p class=\"narrower\">\n    Intended Audience:  This talk is appropriate for users of SAS&apos; syntax-based tools at all \n    experience levels.  The topics/concepts presented assume the attendee is already familiar \n    with core SAS programming concepts such as data set, observation, variable, label, procedure, \n    and data step.\n  </p>\n\n</div>\n\n<p style=\"clear:both\"></p>"
  },
  "m2011q4.php": {
    "title": "NJSUG 2011 Fourth Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>\n    NJSUG 2011 Fourth Quarter Meeting\n    <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">\n      <img src=\"http://sph.umdnj.edu/images/p_nb_adjusted.jpg\" alt=\"umdnj-sph\" border=\"none\" style=\"padding-right: 6px; float:right;\"/>\n    </a>\n  </h2>\n  <p>\n    The meeting was in the morning (9:00am - noon) on Friday, Nov 4th at:\n  </p>\n  <div class=\"c1\">\n  </div>\n  <div class=\"c23\">\n    <p>\n      <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">The UMDNJ - School of Public Health</a>\n      <br/>Room 3A &amp; 3B\n      <br/>683 Hoes Lane West\n      <br/>Piscataway, NJ 08854\n      <br/>(732) 235-9700\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <table class=\"agenda\">\n    <tr>\n      <td class=\"agendatime\">\n        <font color=\"white\">0</font>9:00-<font color=\"white\">0</font>9:20\n      </td>\n      <td class=\"agendatext\">Registration and Continental Breakfast</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">\n        <font color=\"white\">0</font>9:20-10:20\n      </td>\n      <td class=\"agendatext\">\n        Presentation: Multi-sheet Workbooks from SAS&reg; data using the ODS ExcelXP tagset\n        or Another Way to EXCEL using SAS\n        (Cynthia Stetz)\n      </td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">10:20-10:40</td>\n      <td class=\"agendatext\">Break</td>\n    </tr>\n    <!--\n    <tr>\n      <td class=\"agendatime\">10:40-10:45</td>\n      <td class=\"agendatext\">Random Access (announcements)</td>\n    </tr>\n    -->\n    <tr>\n      <td class=\"agendatime\">10:40-11:45</td>\n      <td class=\"agendatext\">Presentation: Predictive Modeling with JMP 9 Pro (Aashish Majethia)</td>\n    </tr>\n    <tr>\n      <td class=\"agendatime\">11:45-noon</td>\n      <td class=\"agendatext\">Door Prize Drawings</td>\n    </tr>\n  </table>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <a name=\"p1\">\n      Multi-sheet Workbooks from SAS&reg; data using the ODS ExcelXP tagset or\n      Another Way to EXCEL using SAS\n    </a>\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://www.nesug.org/Proceedings/nesug11/gr/gr03.pdf\">Paper(pdf)</a>\n    as presented at NESUG 2011\n  </p>\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    Most of us are engaged in providing data to information consumers at least some of the\n    time, and by far the most often requested format is the EXCEL workbook. As the\n    capabilities of Excel have expanded, so have the requests for more and more\n    sophisticated output, and the search for ways to generate this output with the least\n    amount of human effort as possible.\n  </p>\n  <p class=\"narrower\">\n    Fortunately, we can rely on the SAS Institute to supply us with innovative tools to \n    make this task easier. One of those tools that I have recently started using to \n    great effect is the ODS ExcelXP tagset. By harnessing some of the vast capabilities \n    available within this tagset, in concert with the judicious application of macro \n    code and Dynamic Data Exchange (DDE), I am now able to deliver nicely formatted, \n    multisheet native Excel workbooks for any number of subsets of my data as might \n    be desired.\n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    Cynthia A. Stetz (Bank of America / Merrill Lynch)\n    has been a SAS programmer since 1990 when a\n    new employer handed her a SAS manual and told her to rewrite\n    a PLI program in SAS. After seeing how powerful the\n    SAS language was she was hooked! Since then she has\n    applied her always expanding SAS skills to provide\n    information delivery solutions to such industries as\n    Insurance, Education and Financial Services. Cynthia holds a\n    BA in Mathematics from Kean University. In her spare time\n    she enjoys recording computer subject matter for the\n    LearningAlly organization (formerly Recording For The Blind\n    and Dyslexic).\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <span id=\"p2\"></span>Predictive Modeling with JMP 9 Pro\n  </h2>\n\n  <!--\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"#\">Paper(pdf)</a>\n  </p>\n  -->\n\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    JMP Pro is a new product from SAS that helps mining your data like never before.\n    Using push button simplicity, you can build sophisticated models that are easily\n    interpretable. Start taking advantage of your historical data and see long term\n    patterns that you may be missing. With enhanced decision tree algorithms such as\n    bootstrap forest and boosted trees, a new boosted neural nets platform and\n    validation for all of your modeling endeavors, you can take the first step in or\n    your next step in predictive modeling.\n  </p>\n  <p class=\"narrower\">\n    As always, JMP is fully integrated with SAS. Once you have developed your models in \n    JMP, it is simple to generate SAS code to run on your existing SAS infrastructure. \n    Run SAS code from within JMP and even mix in JMP code. This integration enables \n    the quick ad hoc analysis of JMP with the scalability and reporting capabilities \n    of SAS. Come see how to enhance your current capabilities using JMP!\n  </p>\n \n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/majethia.png\" alt=\"majethia\" border=\"none\" style=\"float:left; padding:5px;\"/>\n    Aashish Majethia is a Systems Engineer for JMP, a business unit of SAS specializing \n    in interactive statistical discovery software. Before joining SAS, he worked in \n    business development, engineering and the life sciences. At Raytheon, he developed \n    models and ran simulations of various radar systems. His research experiences span \n    pulmonary physiology, BioMEMS and medical imaging. Majethia earned a Master of Science \n    in biomedical engineering from Boston University and a Bachelor of Science in \n    biomedical engineering from Johns Hopkins University.\n  </p>\n</div>\n\n<p style=\"clear:both\"></p>"
  },
  "m2012q2.php": {
    "title": "NJSUG 2012 Second Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>\n    NJSUG 2012 Second Quarter Meeting\n    <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/UMDNJ-building.jpg\" alt=\"umdnj-sph\" border=\"none\" style=\"padding:2em 2em 0 0;float:right;\"/>\n    </a>\n  </h2>\n  <p class=\"narrower\">\n    The meeting was in the morning (9:00am - noon) on Wednesday, May 30th at:\n  </p>\n  <div class=\"c1\">\n  </div>\n  <div class=\"c23\">\n    <p class=\"narrower\">\n      <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">The UMDNJ - School of Public Health</a>\n      <br/>683 Hoes Lane West\n      <br/>Piscataway, NJ 08854\n      <br/>(732) 235-9700\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <p class=\"narrower\">\n    Registration and Continental Breakfast will start at 9:00am, followed by\n    featured presentations with a short break around 10:30am. The meeting will be \n    wrapped up around noon with announcements and door prize drawing near the end.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <a name=\"p1\">\n      Now You Can Annotate Your SG Procedure Graphs\n    </a>\n  </h2>\n\n  <!--\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://www.nesug.org/Proceedings/nesug11/gr/gr03.pdf\">Paper(pdf)</a>\n    as presented at NESUG 2011\n  </p>\n  -->\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/Dan-Heath-60x66.jpg\" alt=\"Dan Heath\" border=\"none\" style=\"float:left; padding:0;\"/>\n    Dan Heath is a Principal Sortware Developer with SAS. He holds a bachelor's in computer\n    science from North Carolina State University. Heath has been with SAS for more than 18\n    years, working primarily on SAS/GRAPH&reg; and related software.<br/><br/>\n  </p>\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n    Learn how you can create amazing graphics without writing any code using the ODS \n    Graphics Designer. Have you ever had a situation where you wanted to add custom \n    labeling or other graphical features to your SG procedure output but could not \n    find a way to do it?\n  </p>\n  <p class=\"narrower\">\n    Even with all of the plot types and features of the SG procedures, you may have run\n    into this situation. Now, with SAS 9.3, you can add these features directly by using\n    the new annotation support in the SG procedures.\n  </p>\n  <p class=\"narrower\">\n    Learn about the annotation data set functionality and new features, including:\n    <ul class=\"narrower\">\n      <li>Rich text support (including superscripts, subscripts, and Unicode).</li>\n      <li>Transparency support for all primitives.</li>\n      <li>More drawing spaces for easier placement of annotations.</li>\n    </ul>\n  </p>\n  <p class=\"narrower\">\n    An extra presentation! Learn how you can create amazing graphics without writing any \n    code using the ODS Graphics Designer.\n  </p>\n\n</div>\n\n<p style=\"clear:both\"></p>"
  },
  "m2013q4.php": {
    "title": "NJSUG 2013 Fourth Quarter Meeting",
    "content": "<div class=\"container\">\n  <h2>\n    NJSUG 2013 Fourth Quarter Meeting\n    <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">\n      <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/UMDNJ-building.jpg\" alt=\"umdnj-sph\" border=\"none\" style=\"padding:2em 2em 0 0;float:right;\"/>\n    </a>\n  </h2>\n  <p class=\"narrower\">\n    The meeting was in the morning (9:00am - noon) on Friday, November 15th at:\n  </p>\n  <div class=\"c1\">\n  </div>\n  <div class=\"c23\">\n<img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/Nov-15-90x86.jpg\" alt=\"july8th\" border=\"none\" style=\"padding-right: 4px\" align=\"left\" valign=\"top\"/>\n    <p class=\"narrower\">\n      <a href=\"http://sph.umdnj.edu/directions/directions.piscataway.cfm\">The Rutgers School of Public Health (formerly UMDNJ)</a>\n      <br/>683 Hoes Lane West\n      <br/>Piscataway, NJ 08854\n      <br/>(732) 235-9700\n    </p>\n  </div>\n</div>\n\n<div class=\"container\">\n  <h2>Agenda</h2>\n  <p class=\"narrower\">\n    Registration and Continental Breakfast will start at 9:00am, followed by\n    featured presentations with a short break around 10:30am. The meeting will be\n    wrapped up around noon with announcements and door prize drawing near the end.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>Registration</h2>\n  <p class=\"narrower\">\n    Annual dues are just $20 which entitles you to attendance at the meetings, our annual membership \n    directory and future notice of meetings.\n  </p>\n  <p class=\"narrower\">\n    Fill out <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/registration2013.pdf\">the registration form (pdf)</a> and bring it with you at the meeting or use PayPal to remit your dues beforehand.\n  </p>\n  <p class=\"narrower\">\n    Send your PayPal payment to <a href=\"https://web.archive.org/web/20240419193850/mailto:nj.sas.users.group@gmail.com?subject=NJSUG%20Registration\">nj.sas.users.group@gmail.com</a>.\n  </p>\n</div>\n\n<div class=\"container\">\n  <h2>\n    <a name=\"p1\">\n      Presentations:\n    </a>\n  </h2>\n  <h2>\n    <a name=\"p1\">\n      How Mobile Changes the BI Experience\n    </a>\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings13/053-2013.pdf\">Paper(pdf)</a>\n    as presented at SAS Global Forum 2013\n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/nori_murali.jpg\" alt=\"Murali Nori\" border=\"none\" style=\"float:left; padding:5px;\"/>\n     Murali Nori, senior product manager, business intelligence, SAS Inc. has extensive experience \n     in business intelligence and enterprise product development. Special areas of interest are \n     business intelligence, enterprise search and collaboration strategies.\n<br/><br/>\n  </p>\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n     The advent of a new generation of tablets catapulted corporations' use of mobile \n     devices. With SAS&reg; Mobile BI for tablets, anyone who uses BI for work and decision \n     making has a new way to experience BI content. \n   </p>\n  <p class=\"narrower\">\n     Murali will present some end-to-end use cases to demonstrate how revolutionary the \n     user experience is with SAS Mobile BI. He will also demonstrate how easy it is to access \n     and navigate BI content. Discover how BI on mobile devices changes the user \n     experience and the reach of BI content for productivity, decision making, and extracting \n     better ROI. \n  </p>\n</div>\n\n\n<div class=\"container\">\n  <h2>\n    <a name=\"p2\">\n      Whirlwind Tour Around SAS&reg; Visual Analytics\n    </a>\n  </h2>\n\n  <h3 class=\"narrower\">Downloads</h3>\n  <p class=\"narrower\">\n    <a href=\"http://support.sas.com/resources/papers/proceedings13/057-2013.pdf\">Paper(pdf)</a>\n    as presented at SAS Global Forum 2013\n  </p>\n\n  <p class=\"narrower\">\n    <a href=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/m2013q4p2.pdf\">Slide deck(pdf)</a> with FREE self-study links\n   \n  </p>\n\n  <h3 class=\"narrower\">Author</h3>\n  <p class=\"narrower\">\n    <img src=\"https://web.archive.org/web/20240419185616/http://www.njsug.net/images/hs-ted-stolarczyk.jpg\" alt=\"Ted Stolarczyk\" border=\"none\" style=\"float:left; padding:5px;\"/>\n     Ted Stolarczyk, Senior Systems Engineer, SAS Customer Loyalty Team.\n\tHe has supported SAS efforts to position, demonstrate, and prove SAS solutions\n\tfor customers and prospects since 1997.\n\tTed specializes in data management, data visualization, data reporting, systems\n\tadministration, and architecture.\n<br/><br/>\n  </p>\n  <h3 class=\"narrower\">Abstract</h3>\n  <p class=\"narrower\">\n  \tSAS brings a revolutionary approach for analytical-based data visualization,\n\texploration and reporting. Come and join us for a whirlwind tour through SAS\n\tVisual Analytics 6.1, inspired by customer experiences and use cases. We start with\n\tan overview of the technology concept behind SAS Visual Analytics and enter into\n\tthe Hub, leading to various destinations, including the Data Builder, Explorer and\n\tDesigner, ending the journey with Mobile integration. We also offer a sneak peek\n\tinto world of Microsoft Office. Don't worry. SAS coders are not left behind. The final\n\tstop is SAS&reg; Enterprise Guide&reg;, where you learn how to leverage the technology\n\tbehind SAS Visual Analytics through SAS code..\n  </p>\n  <p class=\"narrower\">\n   In addition, Ted will demonstrate how SAS Enterprise Business Intelligence Server\n   can integrate with Visual Analytics.\n  </p>\n\n</div>\n\n<p style=\"clear:both\"></p>"
  },
  "meet1998.html": {
    "title": "20Feb1998 Meeting",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n                \n                  <p align=\"center\"><b>20Feb1998 Meeting</b></p>\n            \n                \n                  <p><span id=\"a\"></span><b>SCL for the Rest of Us: Non-Visual Uses of Screen \n                  Control Language<br>\n                  Michael Davis, Bassett Consulting Services, Inc.</b></p>\n            \n                \n                  <p>Because of the increasing popularity of the SAS System to \n                  create Graphical User Interfaces (GUIs), many have come to \n                  believe that the language used with SAS/AF and SAS/FSP, Screen \n                  Control Language (SCL) is only used with visual objects.</p>\n            \n                \n                  <p>The truth is that SCL can be used in conjunction with or in \n                  place of the SAS macro language to automate SAS batch programs \n                  and to better interface them to the computing environment. \n                  Specifically, SCL programs may be submitted from within batch \n                  programs run on MVS and UNIX host computers. This includes \n                  even those host computers on which SAS/AF is not installed!</p>\n            \n                \n                  <p>This presentation will be an introduction to the subset of \n                  SCL that may be used for non-visual programming applications. \n                  Topics covered include:</p>\n            \n                \n                  <ul>\n                    <li>why SCL code is often easier and better to use than the \n                    other SAS languages (DATA steps and macros)</li>\n                    <li>when to use SCL entries instead of DATA steps or macros</li>\n                    <li>interfacing SCL entries to SAS code executed in batch</li>\n                    <li>how to use the SCL on-line reference materials</li>\n                    <li>using SCL to get the properties of the operating \n                    environment</li>\n                    <li>controlling the execution of SCL code</li>\n            </ul>\n            \n                \n                  <p>No previous background knowledge of SAS/AF or SCL is \n                  presumed. Part of the presentation will be devoted to using \n                  the SCL debugger to learn how SCL programs work and debug \n                  those which do not.</p>\n            \n                \n                  <p><i>Michael Davis is Vice President of Bassett Consulting \n                  Services, Inc. Previously, he worked for Blue Cross &amp; Blue \n                  Shield of Connecticut and the Connecticut Hospital \n                  Association. A SAS user for over 13 years, Michael specializes \n                  in creating SAS/AF FRAME applications. He is a recent past \n                  chairman of the Hartford Area SAS User Group and is a frequent \n                  presenter and section chair at NESUG and SUGI.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"b\"></span><b>Harnessing the Power of SCL Lists<br>\n                  Lisa Horwitz of SAS Institute</b></p>\n            \n                \n                  <p>SCL lists are ordered collections of data stored in memory \n                  and are a powerful tool for applications developers. The \n                  sources of this data can include hard coded values, SAS data \n                  sets, information retrieved from interaction with the \n                  application user or the current SAS session, or the FRAME \n                  entry's objects themselves. This paper explores how to create \n                  and populate SCL lists, how to retrieve and utilize \n                  information from lists, how to manipulate lists, and how to \n                  access some of the lists associated with FRAME entry objects. \n                  An assortment of ideas for using SCL lists will be suggested \n                  as well.</p>\n            \n                \n                  <p><i>Lisa Horwitz is Regional Training Center Manager of the \n                  New York office of SAS Institute. During her 13 years in the \n                  Professional Services Division, she has taught courses and \n                  worked closely with SAS users on technical projects. Her areas \n                  of expertise include applications development, including FRAME \n                  entries and Screen Control Language. Lisa is a frequent \n                  presenter at local and regional SAS Users Group meetings and \n                  at SUGI.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>01May1998 Meeting</b></p>\n            \n                \n                  <p><span id=\"c\"></span><b>Introduction to HTML - No Magic Involved<br>\n                  Bob Bertolatus</b></p>\n            \n                \n                  <p>This talk will explain how web pages are created, how they \n                  are placed on the internet, and how they get delivered to your \n                  browser. While it is truly amazing, there is really no magic \n                  involved. Basic HTML will be discussed as well as a \n                  demonstration of a current Web authoring program.</p>\n            \n                \n                  <p><i>Bob, who serves on the executive board of NJSUG, has \n                  been a computer consultant since 1985, working mostly in the \n                  telecomunications industry. He also teaches Computer \n                  Fundamentals and SAS at Raritan Valley Community College in \n                  North Branch. Bob received his B.S. and M.S. from Rutgers \n                  University in Industrial Engineering/Operations Research and \n                  is returning to school in the fall to study Geography. He has \n                  been a director and the BBS sysop of the Amateur Computer \n                  Group of New Jersey for five years. Bob is the webmaster for \n                  the NJ SAS Users Group homepage. He lives in Somerset with his \n                  wife Leslie and their two daughters and serves as a soccer \n                  coach and league registrar for the local soccer club.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"d\"></span><b>Web Enabling Your SAS Application<br>\n                  James Sun</b></p>\n            \n                \n                  <p>The Internet and intranet have quickly become important \n                  vehicles for information delivery. The Web-enabled SAS \n                  application can greatly benefit organizations which need to \n                  communicate information to large and geographically dispersed \n                  user bases, which may be within or outside the organization. \n                  With SAS/IntrNet Software, users will be able to reduce the \n                  development time and costs that are normally associated with \n                  Web enablement.</p>\n            \n                \n                  <p>This presentation will describe tools and techniques used \n                  to build web applications with the SAS system. Topics covered \n                  include setting up the working environment, generating SAS \n                  output through the Web browser, and developing thin client Web \n                  based SAS application. The implementation of some of the \n                  examples does not require SAS/IntrNet.</p>\n            \n                \n                  <p><i>James Sun is a Sr. System Analyst at Constat Systems \n                  Corporation. He has worked as a statistician and SAS \n                  programmer in the pharmaceutical industry. One of his \n                  specialties is in designing and implementing Intranet based \n                  applications to streamline clinical trial data processing. He \n                  has presented papers at SUGI, NESUG, PharmaSUG and to local \n                  user groups. He is currently an executive committee member of \n                  NJSUG.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>17Sep1998 Meeting</b></p>\n            \n                \n                  <p><span id=\"e\"></span><b>DATA Step in Version 7: What's New?<br>\n                  William F. Heffner</b></p>\n            \n                \n                  <p><i>William F. Heffner is a Principal Systems Developer in \n                  Core Supervisor Development at SAS Institute. He has been with \n                  the Institute for over thirteen years. For the past five \n                  years, he has been the lead developer for the DATA Step, \n                  supporting the compile, resolve, and execute phases, as well \n                  as, the DATA Step view engine and the DATA Step debugger. \n                  Previous development work involved the SAS System for MVS, and \n                  code generation and external I/O subsystems.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"f\"></span><b>Statistical Graphics<br>\n                  Susan Fehrer and Stanley Willsky</b></p>\n            \n                \n                  <p>As the saying goes, a picture is worth a thousand words. \n                  Our presentation will review the principles of good graphic \n                  design for displaying data (also called statistical graphics). \n                  References will be made to experts in the field.<br>\n                  We will discuss how to select the appropriate graphic for the \n                  task at hand based on objectives and the ease of visual \n                  perception. Examples will be shown.</p>\n            \n                \n                  <p>Data can either be presented to accurately reflect the data \n                  at hand or cloud the data so that conclusions cannot be made. \n                  Some examples of poor or misleading graphics will also be \n                  presented. SAS/Graph is the software used to create all of the \n                  graphs used in this presentation.</p>\n            \n                \n                  <p><i>Susan Fehrer is a Sr. Director of Technical Operations \n                  at Target Research Associates, Inc., a Scotch Plains based CRO. \n                  She has over 18 years of pharmaceutical programming experience \n                  and over four years of CRO experience in clinical SAS \n                  programming. Susan is a long-time user of the SAS System. \n                  Susan has an MBA in Quantitative Analysis from Seton Hall \n                  University and a BS in Commerce in the double majors of \n                  Marketing and Decision Sciences &amp; Computers from Rider \n                  University.</i></p>\n            \n                \n                  <p><i>Stanley Willsky holds a BS in Pharmacy, and an MS in \n                  Statistics, both from Rutgers University. Since 1992 he has \n                  been President of Progressive Business Solutions Incorporated; \n                  a company that provides consulting and education services in \n                  information management, study design and analysis, clinical \n                  systems, and surveys.&nbsp; His prior position was at a major \n                  Pharmaceutical Company starting in 1963 as a scientist in R&amp;D \n                  developing new dosage forms, leading to a career in computers \n                  and statistics. He has used SAS extensively for statistical \n                  analysis, graphics, and typical computer system functions.</i><br>\n&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  "
  },
  "meet1999.html": {
    "title": "05Mar1999 Meeting",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n                \n                  <p align=\"center\"><b>05Mar1999 Meeting</b></p>\n            \n                \n                  <p align=\"left\"><b>Additions to the SAS System including ODS<br>\n                  Paul Kent, SAS Institute, Inc., Cary, NC</b></p>\n            \n                \n                  <p>The BASE procedures group (a.k.a. Information Products) at \n                  SAS Institute has been hard at work adding new and useful \n                  features to the heart of the SAS System. Covered are:</p>\n            \n                \n                  <ul>\n                    <li>General additions to SAS Software that should make the \n                    programmers life an easier one.</li>\n                    <li>New SUMMARY/TABULATE options like percentiles, \n                    independent ordering of class variables, and the pre loading \n                    of the class-variable space using formats and/or a data sets \n                    of desired class level values.</li>\n                    <li>The ODS statement for producing output data sets and \n                    HTML output from all SAS procedures, High Fidelity Printing \n                    and more. ODS is an acronym for Output Delivery System.</li>\n                    <li>ODS specific additions to PROC REPORT, PROC TABULATE and \n                    the SAS/Graph Procedures.</li>\n            </ul>\n            \n                \n                  <p><i>Paul has been a SAS User for almost 20 years and has \n                  worked for SAS Institute far longer than he thought he'd hold \n                  any single job. Paul's previous contributions to SAS Software \n                  include PROC SQL; the WHERE Clause and TCP/IP connectivity. \n                  Currently Paul manages the developers responsible for ODS and \n                  the majority of BASE SAS Procedures.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"b\"></span><b>What Your Mother Never Told You About the Query Window<br>\n                  Janet E. Stuelpner, ASG, Inc., Cary, NC</b></p>\n            \n                \n                  <p>The query window is a point and click way to extract data \n                  from a table. With very little instructions, you can create an \n                  SQL program to gather data, manipulate it and create reports. \n                  Does it have limitations? The answer to that is yes. Is there \n                  a work around for those limitations? The answer is also yes. \n                  This presentation will explore what some of the limitations \n                  are in the query window and how to program around them.</p>\n            \n                \n                  <p><i>Janet Stuelpner provides programming support for clients \n                  in may industries that include: pharmaceutical, banking, \n                  brokerage. She also provides both individual and group \n                  technical training when needed at the client sites. Janet has \n                  several degrees in the sciences and has been a SAS user for 18 \n                  years. She has experience in the MVS, UNIX, OS/2 and Windows \n                  environments. Originally a systems programmer, she has now \n                  turned her focus to applications programming. In the last \n                  several years, she has given many presentations at local, \n                  regional and national conferences and has been a frequent \n                  presenter to our group.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>11Jun1999 Meeting</b></p>\n            \n                \n                  <p><span id=\"c\"></span><b>The New FDA Industry Guidelines for Electronic \n                  Regulatory Submissions<br>\n                  Rich Vachal, President Industry Dynamics Associates</b></p>\n            \n                \n                  <p>In January 1999, the FDA's Center for Drug Evaluation and \n                  Research (CDER) published its new Industry Guidelines for \n                  providing Regulatory Submissions in Electronic Format. This \n                  presentation will provide an overview of the key concepts \n                  contained in these Guidelines and discuss specific compliance \n                  issues with respect to bundling SAS datasets, programs and \n                  documentation along with the electronic dossier. It will \n                  conclude with a short demonstation of a guidelines-compliant \n                  integrated review environment utilizing SAS, Microsoft \n                  Explorer and Acrobat Reader.</p>\n            \n                \n                  <p><i>Rich Vachal is President of Industry Dynamics \n                  Associates, Inc. located in Somerset, NJ. Since 1984 IDA has \n                  operated as a pharmaceutical industry technical support firm \n                  specializing in SAS analytical programming and e-submission \n                  software verification and packaging services. He has an \n                  undergraduate degree in International Relations from the \n                  College of William and Mary and a graduate training in \n                  econometrics and statistics from Rutgers. </i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"d\"></span><b>PROC LP for Dummies -or- How to decide which NFL games \n                  to attend<br>\n                  Bob Bertolatus, Consultant</b></p>\n            \n                \n                  <p>In the March NJSUG newsletter, I proposed a problem for \n                  solution in my &quot;Mind Iron&quot; article below. After receiving no \n                  answers I decided to &quot;tackle&quot; it myself. The selection of \n                  fifteen football games to attend in seventeen weeks of \n                  football season is a task we can understand.</p>\n            \n                \n                  <ul>\n                    <li>On &quot;1st down&quot;, the topic of Operations Research will be \n                    introduced.</li>\n                    <li>Secondly, the data step programming required to present \n                    the problem to PROC LP will be attempted.</li>\n                    <li>On third, we will plunge into the problem with varying \n                    preferences for the 1998 season.</li>\n                    <li>Finally, we'll go for broke and modify our work to solve \n                    for 1999 schedule (with 31 teams).</li>\n            </ul>\n            \n                \n                  <p><i>Bob, who serves on the executive board of NJSUG, has \n                  been a computer consultant since 1985, working mostly in the \n                  SAS environment. He also teaches Computer Fundamentals and SAS \n                  at Raritan Valley Community College in North Branch. Bob \n                  received his B.S. and M.S. from Rutgers University in \n                  Industrial Engineering/Operations Research.</i></p>\n            \n                \n                  <p><b>Mind Iron</b><br>\n                  Bob Bertolatus (title refers to pumping iron for the mind, \n                  i.e. mental exercise)</p>\n            \n                \n                  <p>I've come up with an intriguing task that I'd like to \n                  present as a challenge to the New Jersey SAS Users Group. \n                  Suppose one wanted to truly experience the NFL and see each of \n                  the thirty teams in action, in person. Can it be done ? It \n                  seems possible because to see thirty teams, you need to attend \n                  fifteen games. The NFL season extends for seventeen weeks. So \n                  this task should have a solution ( if not many).</p>\n            \n                \n                  <p>Reflecting back to the simpler times of my past when I \n                  studied Operations Research, I recognize this as the type of \n                  problem that OR solved. But back in the 70s, we only \n                  formulated the problem, maybe tried a 3x3 by hand and that was \n                  the end of it. Your mission ( if you decide to accept ) is to \n                  pick only one game each week to attend to see all thirty teams \n                  once and only once. Once the problem is formulated, various \n                  constraints can be added to truly flex your noggin:</p>\n            \n                \n                  <ul>\n                    <li>Avoid/prefer Monday or Sunday night games ( &amp; Thurs &amp; \n                    Sat ), 1:00 pm vs 4:00 pm games</li>\n                    <li>Avoid/prefer artificial turf - domed stadiums</li>\n                    <li>Moderate/extreme temperatures ( North in September, \n                    South in December or vice versa )</li>\n                    <li>Minimize travel ( like analyst John Madden traveling by \n                    bus )</li>\n                    <li>Try to see the weaker teams at home to enjoy closer \n                    games ( maybe cheaper tickets )</li>\n                    <li>Try to see evenly/poorly matched games</li>\n                    <li>Start in week three, then go to for 15 straight weeks</li>\n                    <li>Prefer smaller or larger cities</li>\n            </ul>\n            \n                \n                  <p>The data can be grabbed from the WWW. Use the 1998 season. \n                  Here is a 1998 schedule file with the schedule and additional \n                  information about the teams ( New! 31Mar99 ). If you so \n                  desire, your efforts can be published here to strut your \n                  mental physique in front of your peers ( email me). Have fun!</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>15Sep1999 Meeting</b></p>\n            \n                \n                  <p><span id=\"e\"></span><b>Longitudinal Data Techniques: Looking Across \n                  Observations<br>\n                  Ronald P. Cody, Ed.D, Dept. of Environmental and Community \n                  Medicine, Robert Wood Johnson Medical School</b></p>\n            \n                \n                  <p>One of the most difficult tasks for a SAS� programmer is to \n                  perform operations across multiple observations. For example, \n                  you may have a data set of patient visits, with a variable \n                  number of visits per patient and the data for each visits \n                  stored in a separate observation. Some of the techniques for \n                  working with such data include the RETAIN statement, FIRST. \n                  and LAST. logical variables, the LAG function, and the use of \n                  multiple SET statements (each with a separate FIRSTOBS= \n                  option). Other techniques for summarizing data for each \n                  patient (such as the number of visits, the mean and median of \n                  some variables) involve procedures such as PROC FREQ, PROC \n                  MEANS and PROC UNIVARIATE to output summary data sets. This \n                  talk will demonstrate and discuss these techniques.</p>\n            \n                \n                  <p><i>Dr. Ron Cody is an Associate Professor in the department \n                  of Environmental and Community Medicine at the Robert Wood \n                  Johnson Medical School, Piscataway, New Jersey. He has been a \n                  SAS user for more than 20 years and is the author of Applied \n                  Statistics and the SAS� Programming Language (fourth edition), \n                  published by Prentice Hall. Along with Ray Pass, he has \n                  written a book called SAS� Programming by Example, a book of \n                  annotated SAS examples, published by the SAS Institute as part \n                  of their Books by Users series. His latest books, also \n                  published by the SAS Institute, are The SAS Workbook, and the \n                  SAS Workbook: Solutions. He is currently under contract with \n                  the SAS Institute for a book on Data Cleaning Techniques. Ron \n                  has presented invited papers for numerous local, regional, and \n                  national SAS conferences.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"f\"></span><b>Discontented with PROC CONTENTS? Expand \n                  it with FMTLIB<br>\n                  Irene Mendelson</b></p>\n            \n                \n                  <p>In the pharmaceutical industry, the Food and Drug \n                  Administration (FDA) has issued guidelines on the \n                  documentation it wants to accompany data and programs to \n                  support the electronic form of a New Drug Application (NDA) on \n                  CD-ROM. In short, the FDA thinks that PROC CONTENTS is not \n                  enough to tell the whole story on a data set and wants to see \n                  all of the values and codes for any formats used.</p>\n            \n                \n                  <p>The key is to tap into information about the data set and \n                  its variables that is displayed in PROC CONTENTS and into \n                  information about variable formats and values displayed \n                  through special options on PROC FORMAT. These two information \n                  sources can be joined together using PROC SQL, output into a \n                  spreadsheet, and then copied and pasted into Word, where some \n                  final editing may be required. Although this does require a \n                  few steps, the benefits of this degree of automation are clear \n                  when facing manually combining PROC CONTENTS and PROC FORMAT \n                  output for many data sets with many variables, as is typically \n                  the case with a drug submission.<br>\n                  Although this technique was developed specifically for the \n                  submission of the electronic form of a New Drug Application (NDA) \n                  on CD-ROM, it has wider application for others who are \n                  discontented with what PROC CONTENTS has to offer.</p>\n            \n                \n                  <p><i>Irene Mendelson was first introduced to SAS in 1987 and \n                  has used it off and on since then in her work in the \n                  pharmaceutical industry. She is currently an independent \n                  consultant doing clinical trials programming support at a \n                  major pharmaceutical company. Her areas of interest include \n                  SAS/GRAPH, SAS Macro, and SAS/FSP. She was an invited speaker \n                  for three straight SUGIs, giving various papers and a hands-on \n                  workshop. She has also given papers at NESUG, NYASUG, and \n                  NJSUG. She currently serves on the Executive Committee for the \n                  NorthEast SAS Users Group and is fulfilling the User Group \n                  liaison role, and was the Conference Co-Chair for NESUG'98 in \n                  Pittsburgh, Pennsylvania.</i><br>\n                  <br>\n&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  "
  },
  "meet2000.html": {
    "title": "10-Mar-2000, Friday, 9:00am, JFK Conference Center, Edison NJ",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n                \n                  <p align=\"center\"><b>10-Mar-2000, Friday, 9:00am, JFK \n                  Conference Center, Edison NJ</b></p>\n            \n                \n                  <p><b>Web Publishing Using SAS Software<br>\n                  Chris Bresson, Destiny Corporation, Wethersfield, Connecticut</b></p>\n            \n                \n                  <p>Discussed will be publishing reports, graphs and process \n                  requests over the Web using SAS Software. Several techniques \n                  and issues will be discussed, along with a live demonstration. \n                  Destiny Corporation has extensive experience creating \n                  applications like these for their customers.</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"b\"></span><b>SAS Career Development in the Pharmaceutical Industry<br>\n                  Jean Kim, Smith Hanley Associates, NY and&nbsp; Lloyd Turner, \n                  Ph.D., CIBER Custom Solutions Group, NJ</b></p>\n            \n                \n                  <p>During this time of technological advancement and industry \n                  mergers, it is imperative that a professional manages his or \n                  her own career development. This is especially true in the \n                  pharmaceutical industry where new information technology meets \n                  advancements in bioscience.</p>\n            \n                \n                  <p>This presentation will be in two parts:<br>\n                  Jean Kim will give a broad overview of SAS programming careers \n                  in the context of new developments in the industry, and how \n                  job descriptions have changed to fit the department's needs. \n                  Also, using her recruiting experience, she will speak about \n                  what applicants are seeking in companies and what companies \n                  look for in applicants. Lloyd Turner will use his experience \n                  developing a SAS IT group in a pharmaceutical company to \n                  discuss how new technology is changing the SAS Programmer's \n                  role and what type of new opportunities have emerged in the \n                  past few years.</p>\n            \n                \n                  <p><i>Jean Kim recruits in the areas of Clinical Data \n                  Computing Systems focusing on Clinical SAS Programming, Data \n                  Management, Information Systems, and Database development. \n                  Jean attends and volunteers for various professional societies \n                  to keep informed of the new technological and process \n                  developments in the pharmaceutical industry. Jean's active \n                  presence in the industry offers a wealth of information to her \n                  clients' team building efforts and her candidates' career \n                  development plans.</i></p>\n            \n                \n                  <p><i>Prior to joining Smith Hanley Associates in 1996, Jean \n                  served as the executive director of a social service agency \n                  and has also worked as a director of marketing for a media \n                  production company. She received her BA in Social Science from \n                  University of California at Berkeley and MPA in Public \n                  Administration from Harvard University.</i></p>\n            \n                \n                  <p><i>Lloyd Turner is a senior consultant with the CIBER \n                  Custom Solutions Group in New Jersey. He has managed numerous \n                  client-server and data warehouse applications for clients in \n                  the telecommunications, medical devices, and pharmaceuticals \n                  industries. He is currently directing a business process \n                  re-engineering project involving biostatisticians and clinical \n                  programmers at the Schering-Plough Research Institute. He has \n                  a Ph.D. in Public Policy Analysis from the University of \n                  Pennsylvania and has extensive experience in using SAS tools \n                  in business and academic environments.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>28-Apr-2000, Friday, 9:00am, Raritan \n                  Valley Community Coll., North Branch, NJ</b></p>\n            \n                \n                  <p><span id=\"c\"></span><b>SAS Certified Professional Program<br>\n                  Roger Staum, SAS Institute</b></p>\n            \n                \n                  <p>An article on certification recently appeared in The NESUG \n                  Express, the newsletter for the Northeast SAS Users Group (NESUG). \n                  The article features an interview with two SAS Institute \n                  Quality Partners, Michael Davis and Dave Riba. Davis and Riba \n                  address such questions as &quot;How should clients and employers \n                  view certification?&quot; and &quot;How should you prepare for the \n                  tests?&quot; You can read this informative interview online at\n                  <a href=\"http://www.pace.edu/nesug/EXPRESS/nexp9910.pdf\">\n                  http://www.pace.edu/nesug/EXPRESS/nexp9910.pdf</a></p>\n            \n                \n                  <p><i>Roger Staum is a Technical Consulting Specialist in the \n                  Education Division of SAS Institute. He has been an Institute \n                  employee for six years, based in the New York regional office. \n                  He teaches courses in the Accessing and Manipulating Data, \n                  Presenting Information, and Statistical Analysis curricula.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"d\"></span><b>Overview of AppDev Studio<br>\n                  Carl LaChapelle, SAS Institute</b></p>\n            \n                \n                  <p>AppDev Studio is a suite of products designed for the \n                  development of web based information delivery applications. \n                  Utilizing the power of Java, AppDev studio helps you develop a \n                  variety of web-based clients that expose the computational \n                  power and data services of the SAS MVA server.</p>\n            \n                \n                  <p>In this presentation we'll take a look at each of the \n                  products that are part of AppDev Studio. We'll explore the \n                  features of each of the products, through a series of demos. \n                  We'll then discuss each of the different types of clients you \n                  can build with AppDev studio, and discuss their relative \n                  strengths and weaknesses.</p>\n            \n                \n                  <p><i>Carl LaChapelle is the director of the Display Products \n                  division at SAS Institute. He has been an employee of SAS \n                  Institute for the past fifteen years. He is responsible for \n                  the development of SAS/AF, SAS/FSP, and AppDev Studio \n                  products. Over the years he has worked on many parts of the \n                  SAS system. He is currently working on getting SAS V8.1, and \n                  AppDev Studio 2.0 ready to ship.</i></p>\n            \n                \n                  <p>To find out more about AppDev Studio consider ordering the \n                  following book at the SAS Book Sale�<br>\n                  Getting Started with AppDev Studio(TM), First Edition<br>\n                  Order Number: GO57575<br>\n                  Selling Price: $10.95</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>27-Oct-2000, Friday, 9:00am, Raritan \n                  Valley Community Coll., North Branch, NJ</b></p>\n            \n                \n                  <p><span id=\"e\"></span><b>On visualizing Direct and Partial Correlations<br>\n                  Leonardo E. Auslender, SAS Institute, Inc., Cary, NC</b></p>\n            \n                \n                  <p>Statisticians and data analysts focus on correlations among \n                  pairs of variables to understand the strength of linear \n                  relationships in the data. Since correlations measure \n                  relations among pairs of variables, the standard output is in \n                  matrix form, which tends to be difficult to interpret for a \n                  large number of variables. The superlative analyst can also \n                  incorporate partial correlations to further deepen the \n                  analysis. The hapless data-miner who faces hundreds, if not \n                  thousands, of variables does not long to wade through reams of \n                  outputs of correlations to find &quot;interesting&quot; patterns.</p>\n            \n                \n                  <p>In this paper, the author presents a method that enables to \n                  visualize any number of Pearson (and partial) correlations by \n                  using a Proc-Timeplot-like output.</p>\n            \n                \n                  <p><i>Leonardo Auslender is a statistician and retired \n                  economist with honors with more than 20 years of business \n                  experience and SAS expertise, at present in the Analytical \n                  Consulting group of SAS Institute. His area of expertise is in \n                  the area of Giga-Data Analysis and Methods, and has written \n                  papers and given lectures on missing value imputation, Tree \n                  Regression, Support Vector Machines, Market-Basket Analysis, \n                  Data Base Marketing, CRM, GDP and (Relative Price) Inflation \n                  studies, Expectation Formations, Productivity and Technology \n                  effects in the economy. He was a lecturer of Finance and \n                  Macroeconomics at Rutgers University.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"f\"></span><b>Data Warehousing and MDDB processing \n                  using the SAS system<br>\n                  George Bukhbinder, Palisades Research, Inc., Bernardsville, NJ</b></p>\n            \n                \n                  <p>This paper addresses several factors important to the \n                  successful completion of a large-scale rapid data warehouse \n                  development project in the telecommunications industry. These \n                  factors include:</p>\n            \n                \n                  <ul>\n                    <li>Data model design</li>\n                    <li>Metadata maintenance</li>\n                    <li>Dimensions and hierarchies required for building a \n                    multidimensional database (MDDB)</li>\n                    <li>Internet enabled On Line Analytical Processing (OLAP)</li>\n            </ul>\n            \n                \n                  <p>This paper also includes a demonstration of the \n                  Internet-enabled OLAP built as an interface to a data \n                  warehouse and demonstrates benefits business gains from \n                  building a powerful decision support system for marketing.</p>\n            \n                \n                  <p><i>George Bukhbinder is a president of Palisades Research, \n                  Inc., a database development and analytic consulting firm. He \n                  has over 20 years of experience in marketing database design \n                  and development, market segmentation, and statistical \n                  modeling. He has worked extensively on the development and \n                  implementation of information systems for direct marketing, \n                  strategic planning, and profitability optimization. Mr. \n                  Bukhbinder has a Ph.D. in Statistics</i>.</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  "
  },
  "meet2001.html": {
    "title": "30-Mar-2001, Friday, 9:00am, Raritan Valley Community Coll., North Branch, NJ",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n                \n                  <p align=\"center\"><b>30-Mar-2001, Friday, 9:00am, Raritan \n                  Valley Community Coll., North Branch, NJ</b></p>\n            \n                \n                  <p><b>You can do THAT with SAS Software? Using the socket \n                  access method to unite SAS with the Internet<br>\n                  David Ward, President, InterNext, Inc.</b></p>\n            \n                \n                  <p>The addition of the socket access method to version 6.11 of \n                  the SAS System provided the Base, Macro, and SCL languages \n                  with a simple way to use the standard TCP/IP network protocol. \n                  TCP/IP is the protocol that is used to access virtually all \n                  types of network servers, like FTP, Telnet, Web, etc.</p>\n            \n                \n                  <p>In the years since version 6.11 was released, the Internet \n                  has grown exponentially and become a vital part of virtually \n                  all technology-based businesses. Using the Socket Access \n                  Method, the SAS system can interact with the servers that make \n                  up the Internet, as well as become a server itself.</p>\n            \n                \n                  <p>This paper will present simple implementations of the \n                  following TCP/IP protocols and discuss practical uses for \n                  each: HTTP (Hypertext Transfer Protocol), SMTP (Simple Mail \n                  Transfer Protocol), POP3 (Post Office Protocol), FTP (File \n                  Transfer Protocol), Telnet, and SAS to SAS client/server \n                  processing. Uses of these protocols will include building a \n                  SAS-based web server, dynamic publishing of SAS data on the \n                  Internet without SAS/Intrnet, sending email directly from the \n                  SAS system without the need to use a third-party's email \n                  software, and reading web pages from the Internet without \n                  using the URL access method.</p>\n            \n                \n                  <p><i>David Ward is president of InterNext, Inc., a software \n                  development company based in central New Jersey. He has been \n                  using SAS for 4 years and uses it in conjunction with many \n                  other programming tools including Perl, Java, Microsoft Visual \n                  Studio, and others. He has a B.A. in Math from Rutgers \n                  University. He supervised clinical programming at Data \n                  Analysis System, Inc. from 1997 to 1999, including teaching \n                  and planning SAS training. He the moved into software \n                  development in 1999 working for DZS Software Solutions, Inc. \n                  David is currently president of InterNext, Inc., a software \n                  development company dedicated to SAS software solutions, \n                  specializing in Internet applications.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"b\"></span><b>Analyzing the stock market using SAS software<br>\n                  Jim Arvesen, President, Strategic Solutions and Services, Inc.</b><br>\n                  <br>\n                  SAS has been very successful in the areas of clinical \n                  development, analyzing sales and marketing data, as well as \n                  many financial problems. However, it has not found much use in \n                  day-to-day applications in handling the vast amounts of data \n                  in the stock market. There are over 1000 stocks that one might \n                  want to track on an hourly (or more frequent) basis. In \n                  addition to data management, SAS offers the capability of \n                  analyzing models associated with these data. Some examples \n                  will be presented. Other topics of discussion will include \n                  slippage, the difference in the bid/ask spread before and \n                  after decimalization, the use of multivariate procedures in \n                  SAS, and why univariate procedures are not adequate to the \n                  task of finding an edge. Also presented is how SAS can read \n                  stock data directly from the Internet, expediting your data \n                  acquisition.</p>\n            \n                \n                  <p><i>Jim Arvesen has an A.B. in Math and Statistics at UC \n                  Berkeley, and a Ph.D. in Statistics from Stanford. He taught \n                  at Purdue, Columbia, NYU and Fairleigh-Dickinson University, \n                  worked at Pfizer for over 20 years, first in clinical \n                  development, subsequently in Marketing Research. Dr. Arvesen \n                  started Data Analysis Systems, Inc. in 1994 with 4 partners \n                  which grew to over 80 staff in 1998, and sold to Quintiles \n                  Transnational. He is currently president of Strategic \n                  Solutions and Services, Inc. and living on a working farm in \n                  Lebanon, New Jersey.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>07-Jun-2001, Thursday, 9:00am, Rutgers \n                  Labor Education Center, New Brunswick, NJ</b></p>\n            \n                \n                  <p><span id=\"c\"></span><b>Creating and Using Summary Data Sets - Additions In SAS, \n                  V8<br>\n                  Ron Cody, UMDNJ, Piscataway, New Jersey</b></p>\n            \n                \n                  <p>Several SAS procedures produce summary output data sets. \n                  PROC MEANS (a.k.a. PROC SUMMARY) and PROC FREQ come to mind. \n                  This talk will discuss how to produce and use these summary \n                  data sets. Some of the version 8 additions to these procedures \n                  will be discussed as well. For example, PROC MEANS now \n                  includes a CHARTYPE option and a TYPES statement as well as an \n                  AUTONAME output option (which automatically provides names to \n                  the various output statistics). You may actually discover the \n                  mystery of the underscore variables _TYPE_ and _FREQ_. So, \n                  come and learn some new neat stuff!</p>\n            \n                \n                  <p><i>Dr. Ron Cody is a Professor in the department of \n                  Environmental and Community Medicine at the Robert Wood \n                  Johnson Medical School, Piscataway, New Jersey. He has been a \n                  SAS user for more than 20 years and is the author of &quot;Applied \n                  Statistics and the SAS� Programming Language&quot; (fourth \n                  edition), published by Prentice Hall. He has also authored or \n                  co-authored several books for the SAS Institute as part of \n                  their Books by Users (BBU) series. Ron has presented invited \n                  papers for numerous local, regional, and national SAS \n                  conferences.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"d\"></span><b>SAS Version 8.2 enhancements<br>\n                  Scott Vodicka, SAS, Cary, North Carolina</b></p>\n            \n                \n                  <p><i>Scott received a BS in Computer Science from North \n                  Carolina State University. Scott was a software developer \n                  writing C and C++ applications for 9 years. He joined SAS in \n                  1996 as a Systems Engineer for the Northeast Region focusing \n                  on data warehousing, business intelligence, and web \n                  Technologies. In 1999 he moved to the North American Marketing \n                  department as the Integration Technologies Product Marketing \n                  Manager. He moved to his current position as a Technology \n                  Strategist in World Wide Marketing in September 2000. Since \n                  January he has focused on wireless technologies.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>13Sep2001, Thursday, 9:00am, Rutgers \n                  Labor Education Center, New Brunswick, NJ</b></p>\n            \n                \n                  <p><span id=\"e\"></span><b>Covariant Method for Analysis of Stability Data<br>\n                  Clayton Rasmussen, New Jersey</b></p>\n            \n                \n                  <p>This presentation will demonstrate how to compute several \n                  regression equations using an Analysis of Covariance (ANCOVA) \n                  procedure for various lot and package combinations. It will \n                  also demonstrate how to construct estimate statements to \n                  compare regression slopes for factors that can affect the rate \n                  of degradation.</p>\n            \n                \n                  <p>Additionally, this presentation will address the designing \n                  of simulation experiments, which are used to show how random \n                  errors affect the distribution of probability values from the \n                  estimate statements. By assigning the known regression slopes \n                  to the factors that can affect the degradation rate, \n                  simulation experiments were generated by adding random errors \n                  to the assay values.</p>\n            \n                \n                  <p><i>Clayton Rasmussen recently retired from \n                  Parke-Davis/Pfizer after 31 years in the Product Development \n                  department of Warner-Lambert/Parke-Davis. He began using SAS \n                  to analyze and present laboratory data when SAS was only a \n                  mainframe application, but since then has used SAS on DOS, \n                  OS/2, Windows/NT and Unix. In 1989, he began analyzing \n                  stability data for regulatory submissions. Clayton used the \n                  GLM procedure to compute the regression line and confidence \n                  interval and the GPLOT procedure to plot the results. In \n                  addition to analyzing laboratory data, he held the leadership \n                  role for several laboratory systems, including the Beckman \n                  LabManager (Laboratory Information Management System), data \n                  acquisition systems (PeakPro and HP LAS), and the Local Area \n                  Network in Product Development.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"f\"></span><b>An Application of PROC NLP to Survey Sample Weighting<br>\n                  Talbot Katz, New Jersey</b></p>\n            \n                \n                  <p>For surveys and other studies, we may need to analyze or \n                  model a random sample of a large population. In order to \n                  extrapolate the results in the sample back to the original \n                  population, subgroups of the sample must be weighted in \n                  proportion to their size (or other importance measure) within \n                  the original population. (We assume no sample bias or \n                  stratification.)</p>\n            \n                \n                  <p>Typically the weight for each individual in sample subgroup \n                  i is equal to (p{i}/P)*(S/s{i}), where P is the size of the \n                  original population, S is the size of the sample, p{i} is the \n                  size of subgroup i in the original population, and s{i} is the \n                  size of subgroup i in the sample; the sum of these numbers \n                  over the whole sample is equal to S (the weights of the \n                  subgroups in the sample are redistributed in proportion to the \n                  weights of those subgroups within the population). This \n                  weighting formula does not apply when subgroups of the sample \n                  are empty.</p>\n            \n                \n                  <p>Usually empty subgroups are not important by themselves, \n                  and sometimes such subgroups can be folded in with non-empty \n                  subgroups. But there are cases when this is not practical. For \n                  example, suppose we are studying a population of IT \n                  professionals that has both employees and consultants, each of \n                  whom can be either a SAS user or unenlightened (i.e., a non-SAS \n                  user). If our sample of consultants who are not SAS users is \n                  empty, and if we wish to study differences between employees \n                  and consultants and differences between SAS-users and non-SAS-users, \n                  we cannot combine the weight of the non-SAS-using consultants \n                  into any of the remaining subgroups. A quadratic minimization \n                  algorithm is presented, via PROC NLP, to weight all the \n                  non-empty sample subgroups in such a way as to retain the most \n                  important properties of the original population. A brief \n                  introduction is given to PROC NLP, including discussion of \n                  some options which allow flexible treatment of this problem.</p>\n            \n                \n                  <p><i>Talbot Katz is a SAS consultant who has modeled for the \n                  telecommunications, credit, and pharmaceutical industries \n                  (they have remarkably similar wardrobes!). He has been a \n                  member of NJSUG for a random sample of the past eight years.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>06Dec2001, Thursday, 9:00am, Rutgers \n                  Labor Education Center, New Brunswick, NJ</b></p>\n            \n                \n                  <p><span id=\"g\"></span><b>Intro to the Macro Map<br>\n                  Russ Lavery, Saad Anbari, Musa Nsereko, Philadelphia, PA</b></p>\n            \n                \n                  <ul>\n                    <li>Macros recall text and conditionally execute code</li>\n                    <li>The three SAS compiles and the three SAS executes</li>\n                    <li>Review of tokenizaton and regular SAS job</li>\n                    <li>Assigning/resolving a macro variable (what causes \n                    errors)</li>\n                    <li>Macro Compiling/Execution of a Macro Program (what \n                    causes errors)</li>\n                    <li>Evaluating &amp;&amp; and &amp;&amp;&amp; and &amp;&amp;&amp;&amp;</li>\n            </ul>\n            \n                \n                  <p><span id=\"h\"></span><b>The Macro Reference Environment and \n                  Methods of Influencing Macro Execution<br>\n                  Russ Lavery, Saad Anbari, Musa Nsereko, Philadelphia, PA</b></p>\n            \n                \n                  <ul>\n                    <li>The macro referencing environment</li>\n                    <li>Global and local macro variables</li>\n                    <li>Logic for update vs. creation of macro variables</li>\n                    <li>%include</li>\n                    <li>call execute</li>\n                    <li>Macro looping (%do i = 1 to &amp;num)</li>\n            </ul>\n            \n                \n                  <p><i>Russ Lavery is an independent contractor who has used \n                  SAS for 15 years. He specializes in using SAS and statistics \n                  to solve business problems.</i></p>\n            \n                \n                  <p><i>Saad Anbari is a SAS programmer for Sanofi-synthelabo \n                  and has used SAS for 5 years. Saad has experience in using SAS \n                  in the health care industry. SAS Certified Professional.</i></p>\n            \n                \n                  <p><i>Musa Nsereko is is a SAS programmer for \n                  Sanofi-synthelabo and has used SAS for 7 years. Musa has \n                  experience in using SAS in the health care industry. SAS \n                  Certified Professional.</i><br>\n&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  "
  },
  "meet2002.html": {
    "title": "Winter Meeting, Friday 08Mar2002, 9am, Rutgers Labor Education Center, New Brunswick NJ",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n                \n                  <p align=\"center\"><b>Winter Meeting, Friday 08Mar2002, 9am, \n                  Rutgers Labor Education Center, New Brunswick NJ</b></p>\n            \n                \n                  <p><b>You Could Look It Up: An Introduction to SASHELP \n                  Dictionary Views<br>\n                  Michael Davis, Bassett Consulting Services, Inc., CT</b><br>\n                  <br>\n                  Ever wonder what titles were already set in a batch SAS \n                  session? Need a list of the members in a library so your macro \n                  can automatically hack at each one? Curious as to how many \n                  observations are in that data set without running a procedure \n                  or DATA step? Want to see what macro variables already exist? \n                  Anytime that one has a question about what is going on in \n                  their SAS session, they can answer it the same way that SAS \n                  itself does the task... they can look it up in the SASHELP \n                  dictionary views.</p>\n            \n                \n                  <p><i>Michael Davis is Vice President of Bassett Consulting \n                  Services, Inc., a SAS Alliance Silver Member. An independent \n                  consultant since 1994, he previously worked for Blue Cross &amp; \n                  Blue Shield of Connecticut and the Connecticut Hospital \n                  Association. A SAS user since 1985, Michael specializes in \n                  developing custom web-enabled and full-screen decision support \n                  systems using SAS/IntrNet, SAS/AF FRAME, and other SAS \n                  products, including SAS/Warehouse Administrator. He is a past \n                  chairman of the Hartford Area SAS User Group and is a frequent \n                  presenter at NESUG and SUGI. Michael is also the past \n                  president of the Connecticut Chapter of the Independent \n                  Computer Consultants Association.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>Spring Meeting, Friday 07Jun2002, 9am, \n                  Rutgers Labor Education Center, New Brunswick NJ</b></p>\n            \n                \n                  <p><span id=\"c\"></span><b>Choice of Development Tool for the User Interface of a \n                  Client-Server Application in a SAS Environment<br>\n                  Barry R. Cohen</b><br>\n                  <br>\n                  Application developers in SAS environments regularly face the \n                  question about what tool to use to build the client-based user \n                  interface of their client-server applications. These are \n                  environments where (1) the data is in server-based SAS data \n                  sets, (2) the primary processing is done with server-based SAS \n                  Software applications that cover file management, analysis, \n                  and reporting, and (3) the user interface, or front-end, is \n                  client-based and is used primarily to direct and control the \n                  processing and to present results. Although the server-based \n                  back-end is all SAS-based, the front-end user interface can \n                  be, but does not have to be, written with SAS Software. The \n                  choice of a front-end tool has never been simple because of \n                  trade-offs involved. But this tool choice has over time become \n                  even less clear because (1) non-SAS front-end tools have \n                  eclipsed the primary SAS tool (SAS/AF) in popularity, (2) SAS \n                  has stopped growing the SAS/AF tool, and (3) SAS has developed \n                  a new tool, AppDev Studio. AppDev Studio is primarily used to \n                  build the client and server sides of Web-enabled SAS \n                  applications, but it can actually build a front-end to any \n                  server-based SAS application and set of data. This paper \n                  evaluates SAS/AF, SAS AppDev Studio, and the non-SAS tool \n                  class, (with Visual Basic as a prime example), against a \n                  series of relevant performance factors. Information is \n                  provided to structure and contribute to the decision about \n                  which front-end development tool to use.</p>\n            \n                \n                  <p><i>Barry Cohen is a systems development consultant and \n                  President of Planning Data Systems, Inc, with over 20 years \n                  experience, much involving SAS Software.</i></p>\n            \n                \n                  <p><i>Mr. Cohen has provided services to a variety of \n                  industries, including a focus in the pharmaceutical industry. \n                  He is a co-founder and President of PhilaSUG, the Philadelphia \n                  SAS Users Group. Mr. Cohen is an accomplished author and \n                  invited speaker at SAS and other conferences, and occasionally \n                  chairs SAS user group conference sections.<br>\n                  His most recent experiences have involved design of a SAS \n                  Program Development Environment, performance testing of SAS-based \n                  client/server configurations for analytic processing, and \n                  efficiency tools for statistical program development in \n                  clinical trials.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"d\"></span><b>SAS and ODS / Publishing to a Web Site, IBM / OS390 \n                  Implementation<br>\n                  Sanja Batljan</b></p>\n            \n                \n                  <p>How often users have asked you if you can reproduce a \n                  report that they have gotten two months ago? If you do not \n                  anticipate this you may find yourself struggling to identify \n                  historic data and recreate the report. One approach to get \n                  around this problem is to save a hard copy of the all monthly \n                  reports in the folder. Another alternative is to save a snap \n                  shot of data from 2 months ago in order to rerun the report. \n                  It is always easy to forget to do these steps and then you \n                  might be in trouble.</p>\n            \n                \n                  <p>Thanks to the Output Deliver System (ODS) we can put any \n                  procedure output into an HTML file and publish the file on \n                  company's Intranet. Users can then browse those reports \n                  whenever they want and for all previous time periods.</p>\n            \n                \n                  <p>This paper will demonstrate how to keep track of historical \n                  reports in HTML format and how to navigate those reports. The \n                  paper will also cover drill-down links using PROC REPORT on \n                  the sample report for each time period. Since the report \n                  program is running on OS390 this paper will indicate some \n                  specifics of the ODS HTML statement in OS390 operating \n                  environment. The WEB server in this case is on UNIX and this \n                  paper will demonstrate how to transfer HTML files from OS390 \n                  system to UNIX using FTP access method within SAS program on \n                  OS390.</p>\n            \n                \n                  <p><i>Sanja Batljan is Senior Business Analyst in the Database \n                  Marketing and Analysis Department of the UBS PaineWebber. She \n                  has been SAS user for 6 years. She has been working as SAS \n                  Programmer in the financial and health care industry and has \n                  experience in the Windows, UNIX, and MVS environments. She is \n                  SAS Certified Professional and active participant in NESUG.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>Early Autumn meeting - Thursday, \n                  10Oct2002, 9am, Rutgers Inn &amp; Conference Center, New Brunswick</b></p>\n            \n                \n                  <p align=\"left\"><br>\n                  <span id=\"e\"></span>\n                  <b>To Web or not to Web<br>\n                  David Ward</b><br>\n                  <br>\n                  The SAS(r) programming community has been bombarded with \n                  demos, presentations, user group papers and white papers \n                  outlining why we should move our programs to the web. Even \n                  with so much emphasis placed on new and exciting ways to \n                  access SAS software, most programmers still sit in front of \n                  good 'ol Base SAS day in and day out. In this presentation we \n                  will explore how you can use SAS with the Internet, whether or \n                  not you should actually do this, and why many programmers have \n                  avoided it altogether.</p>\n            \n                \n                  <p align=\"left\"><i>David Ward is Technology Director for \n                  InterNext, Inc., a software and consulting company located in \n                  New Brunswick, New Jersey focusing on SAS-based solutions. \n                  Before founding InterNext in 2000, he previously worked in the \n                  pharmaceutical industry writing commercial software \n                  applications. InterNext has drawn from its consulting and \n                  application development experience to build and sell several \n                  commercial applications. He is an active speaker at local and \n                  regional SAS user groups.</i></p>\n            \n                \n                  <p align=\"left\">&nbsp;</p>\n            \n                \n                  <p align=\"left\"><span id=\"f\"></span><b>PROC TABULATE: Doin' it in STYLE!<br>\n                  Ray Pass &amp; Sandy McNeill</b><br>\n                  <br>\n                  The advent of the SAS Output Delivery System (ODS to its \n                  friends) has turned SAS reports from machine-generated, black \n                  &amp; white monospace bores into people-produced, productive and \n                  reader-friendly information displays. One of the main \n                  principles underlying ODS is the use of Table and Style \n                  definitions (also known as Table and Style templates). Most \n                  procedures have a standard output layout structure and rely on \n                  their Table and Style definitions to govern the cosmetic or \n                  stylistic appearance of their tables. Certain procedures \n                  (REPORT, TABULATE, etc), however, by the very nature of their \n                  complete structural customizability, do not rely on fixed \n                  external table definitions. For these procedures, stylistic \n                  customizations are performed through the use of the STYLE \n                  option, an ODS concept which is integrated into the heart of \n                  the procedures' syntax. This presentation will demonstrate the \n                  use of STYLES in the TABULATE procedure.</p>\n            \n                \n                  <p align=\"left\"><i>Ray Pass is an independent SAS consultant \n                  and has been using the SAS System for too many years. He is \n                  the co-author, with Ron Cody, of &quot;Programming SAS by Example&quot; \n                  (1995) and has delivered many invited papers at national, \n                  regional and local SAS user groups. Ray's primary areas of \n                  expertise in the SAS System are report generation and data \n                  manipulation. In addition to teaching SAS courses, Ray has \n                  also been quite active in organizing and participating in SAS \n                  user group activities on various levels. Ray was one of the \n                  founders of both the New York Area SAS Users Group (NYASUG) \n                  and the NorthEast SAS Users Group (NESUG.) Ray co-chaired the \n                  first two NESUG annual conferences ('88, '89) and has been a \n                  Section Chair at many SAS User Group International (SUGI) \n                  annual conventions.</i></p>\n            \n                \n                  <p align=\"left\">&nbsp;</p>\n            \n                \n                  <p align=\"left\">&nbsp;</p>\n            \n                \n                  <p align=\"center\"><b>Late Autumn meeting - Tuesday, 10Dec2002, \n                  9am, SAS offices, Bedminster NJ</b></p>\n            \n                \n                  <p align=\"left\"><span id=\"g\"></span><b>ODS Output - A Discussion of Some Examples<br>\n                  Cynthia Stetz</b></p>\n            \n                \n                  <p align=\"left\">Even if you have never written an ODS \n                  statement, if you are using SAS version 7 or above, you are \n                  using the SAS Output Delivery System. In prior versions, SAS \n                  procedures managed their own output and were limited to \n                  producing monospace SAS listings. Some procedures created \n                  output datasets, and some did not. Now, the SAS Institute has \n                  'filtered out' this processing from the procedures and created \n                  the SAS Output Delivery System.</p>\n            \n                \n                  <p align=\"left\">In this presentation, we will briefly describe \n                  ODS, and then discuss several output examples, including HTML, \n                  RTF, PDF and high-resolution printer output. We will show how \n                  ODS interacts with procedures and the data step, and how you \n                  can combine multiple elements, such as text and a graph on one \n                  page. Please note: this presentation is based on SAS version \n                  8.2; some ODS features discussed are not production in prior \n                  releases.</p>\n            \n                \n                  <p><i>Cynthia Stetz is a SAS Certified Professional, with over \n                  12 years experience using the SAS System. She specializes in \n                  data management and delivery, turning data into information \n                  for clients in industries such as finance, education, and \n                  insurance. Cynthia has been a speaker at several SUGI, NESUG \n                  and NYSUG meetings, and at SAS seminars in South Korea and \n                  Japan.</i></p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  <p><span id=\"h\"></span><b>SAS Version 9 Features<br>\n                  Terry Drucker, SAS</b></p>\n            \n                \n                  <p>SAS Version 9 revolves around four major cornerstones: \n                  usability, scalability, interoperability, and manageability. \n                  This discussion will focus on new products, features, \n                  functions, and solutions within SAS to meet these four \n                  cornerstones. A timeline of SAS V9 as well as supported \n                  platforms will also be discussed.</p>\n            \n                \n                  <p>Demo session by SAS Systems Engineers including</p>\n            \n                \n                  <p>INTELLIGENT ARCHITECTURE<br>\n                  <br>\n                  + Data Warehousing<br>\n                  + Business Intelligence<br>\n                  + Advanced Analytics including Data Mining<br>\n                  + Foundation Technologies</p>\n            \n                \n                  <p>ENTERPRISE INTELLIGENCE - Strategic Performance <br>\n                  <br>\n&nbsp;</p>\n            \n                \n                  <p>&nbsp;</p>\n            \n                \n                  "
  },
  "meet2003.html": {
    "title": "Late Autumn meeting - Tuesday, December 9, 2003, 9am - SAS Bedminster, NJ",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n            <p></p>\n                          \n             \n                  <p align=\"center\"><b>Late Autumn meeting - Tuesday, December \n                  9, 2003, 9am - SAS Bedminster, NJ</b></p>\n            <p align=\"left\"><span id=\"g\"></span><b>Using SAS Drug Development as a Report Management \n            Application<br>\n            Barry R. Cohen, Planning Data Systems, Inc.</b><br>\n            <br>\n            Many statisticians and statistical programmers in the pharmaceutical \n            industry will first come to know SAS Drug Development as a product \n            that addresses their regulatory - compliance issues (auditing, \n            versioning, and security) as they develop their on-going analysis \n            programs, data, and documents for NDA filings. However, the product \n            provides a full, flexible processing environment that can be used in \n            other ways. In this paper, I examine standard features of SAS Drug \n            Development that allow it to serve as a Web-enabled report \n            management application for a library of SAS-based report programs. \n            Such an application could cover typical functions such as: report \n            program loading; report parameter solicitation; report program \n            selection and execution; and report output file viewing.</p>\n            <p align=\"left\"><i>Barry Cohen is a systems development consultant \n            and President of Planning Data Systems, Inc, with over 20 years \n            experience, much involving SAS Software.</i></p>\n            <p align=\"left\"><i>Mr. Cohen has provided services to a variety of \n            industries, including a focus in the pharmaceutical industry. He is \n            a co-founder and President of PhilaSUG, the Philadelphia SAS Users \n            Group. Mr. Cohen is an accomplished author and invited speaker at \n            SAS and other conferences, and occasionally chairs SAS user group \n            conference sections.<br>\n            His most recent experiences have involved design of a SAS Program \n            Development Environment, performance testing of SAS-based \n            client/server configurations for analytic processing, and efficiency \n            tools for statistical program development in clinical trials.</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"left\"><span id=\"h\"></span><b>Not quite &quot;PROC AUTOBUCKET&quot;<br>\n            Bob Bertolatus, SAS Certified Advanced Programmer, Somerset, NJ</b><br>\n            <br>\n            Data occurs and is naturally viewed as stacks or columns of values \n            of varying height for individual units-of-interest. Usually the \n            stacks are flattened to a single row to create a homogenous \n            observation for each unit. To create these rows, the stacked values \n            are distributed across each row into buckets. In SAS, a data step \n            can be crafted to perform this reshape of the data, utilizing \n            conditional statements to distribute the values. When the bucket \n            count becomes large (tens or greater), the data step approach grows \n            in complexity and becomes less flexible. This paper will show how to \n            replace the conditional data step with a combination of PROC FORMAT, \n            PROC SUMMARY, and PROC TRANSPOSE to almost make the bucketing \n            process table driven. As such, this method can be readily scaled to \n            hundreds or thousands of buckets (columns).</p>\n            <p align=\"left\"><i>Bob is a computer consultant, providing data \n            processing solutions using SAS to the telecommunications, insurance, \n            and pharmaceutical industries in central New Jersey for nearly \n            twenty years. He also is an adjunct instructor at Raritan Valley \n            Community College in North Branch, NJ, teaching courses in Computer \n            Literacy, advanced Unix and SAS. He is a MetroStars (soccer) fan \n            because somebody has to be and enjoys traveling either with his \n            family or by motorcycle touring.</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"center\"><b>Fall meeting - Friday, October 3, 2003, 9am, \n            Rutgers Labor Education Center, New Brunswick, NJ</b></p>\n            <p align=\"left\"><b>&quot;LAG with a WHERE&quot; and other DATA Step Stories<br>\n            Neil Howard, Manager of Statistical Programming, Ingenix \n            Pharmaceutical Services, Basking Ridge, NJ</b></p>\n            <p align=\"left\"><br>\n            <br>\n            <b>ETL Studio on V9.1<br>\n            Gary Mehler, SAS, Cary, NC</b></p>\n            <p align=\"left\"><br>\n&nbsp;</p>\n            <p align=\"center\"><b>Spring meeting - Friday, June 6, 2003, 9am, \n            Rutgers Labor Education Center, New Brunswick, NJ</b></p>\n            <p align=\"left\"><span id=\"e\"></span><b>Introduction to Mapping with SAS/GRAPH<br>\n            Mike Zdeb</b><br>\n            <br>\n            You can create maps with SAS by using PROC GMAP, one of the \n            procedures available within SAS/GRAPH. Like other SAS procedures, \n            PROC GMAP can be used on a number of levels. At a beginning level, \n            you can produce a number of different types of maps using very \n            little SAS code and no procedure options. At a more advanced level, \n            you can create maps with labeled areas and hyperlinks to other \n            information (examples).</p>\n            <p align=\"left\">This paper examines the two extremes of SAS/GRAPH \n            mapping. First, the basics are explained, giving you enough \n            information to allow you to create several different types of maps \n            with SAS/GRAPH. Then, some advanced features (including hyperlinks, \n            map popups, and animation) are shown, concentrating on creating maps \n            for access on the web. A New Jersey example can be found here.</p>\n            <p align=\"left\"><i>Mike Zdeb is an assistant professor in the \n            Department of Epidemiology at the U@Albany School of Public Health. \n            He teaches both introductory and advanced SAS courses, concentrating \n            on data organzation and data management. Mike has been a SAS user \n            since 1986 and recently completed &quot;Maps Made Easy Using SAS&quot;, a book \n            published by SAS as part of the books-by-users program.</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"left\"><span id=\"f\"></span><b>SyncSort � Making SAS applications run faster<br>\n            Suzanne Malzacher</b></p>\n            <p align=\"left\">Do you want better performance from your long \n            running SAS jobs? Is there any application/process that takes hours \n            to run? Is there any SAS application that processes millions of \n            records? See how you can improve SAS application performance through \n            SyncSort. SyncSort processes data and records much faster than \n            typical applications. By implementing SyncSort to replace various \n            SAS processing, SAS application elapsed time decreases dramatically. \n            The key functions that SyncSort accelerates include:<br>\n            <br>\n            <br>\n            * Aggregation � Summarize data for equally keyed records<br>\n            * Cleansing � Correct or eliminate invalid data<br>\n            * Computation - Perform arithmetic operations on data to create \n            computed values<br>\n            * Copy � Copy data<br>\n            * Data creation - Create data fields based on conditions in the \n            source data<br>\n            * Extraction � Select records or fields from various data sources<br>\n            * Filtering � include/omit to group records for different processing<br>\n            * Integration - Combine data from multiple sources<br>\n            * Join - Join data from different sources based on a common key<br>\n            * Merge � Merge pre-sequenced data from different sources<br>\n            * Ordering - Sort data according to key fields<br>\n            * Pattern matching � frequently used for conditional processing of \n            web log data<br>\n            * Partitioning � Prepare data for parallel database loads<br>\n            * Segmentation � Route source data to different targets<br>\n            * Transformation - Reformat, convert, rearrange data fields<br>\n            * Validation � Verify the correctness of the data</p>\n            <p align=\"left\">The presentation will review 3 case studies where \n            SyncSort made a significant difference in SAS performance. Learn \n            about the role of SyncSort in developing and improving performance \n            of SAS applications. See a demonstration of SyncSort's GUI - an easy \n            to use front end to simplify maintenance and modification of \n            applications and decrease application development time.</p>\n            <p align=\"left\"><i>Suzanne Malzacher is a Software Engineer at \n            Syncsort Incorporated, focusing on creating SyncSort applications in \n            UNIX, NT and VMS environments. With over 13 years experience at the \n            company, Suzanne has extensive experience in writing programs in C, \n            C++, COBOL and Perl. In addition, she is responsible for debugging \n            customer applications, creating shell scripts, and ensuring source \n            integrity. Suzanne has also built numerous SyncSort applications for \n            various customers to reduce their elapsed processing time in such \n            areas as data warehousing, data mining, data marts, CRM, ERP, DSS, \n            BI, Oracle Financials, SAS applications and legacy migration. She \n            earned her MS in Computer Science from Iona College.</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"center\"><b>Late Winter meeting - Tuesday, 18Mar2003, 9am, \n            Bedminster, NJ</b></p>\n            <p align=\"left\"><span id=\"a\"></span><b>Data about Data: An Introduction to Dictionary \n            Tables<br>\n            Frank DiIorio</b></p>\n            <p align=\"left\">Dictionary tables have been part of the SAS System \n            since Version 6.07. Since their introduction, they have become an \n            increasingly popular part of the SAS programming tool box. They, and \n            their associated views in the SASHELP library, are meta-data, or \n            &quot;data about data.&quot; They contain information about SAS datasets, \n            catalogs, external files, and system options. And, best of all, the \n            SAS programmer does not need to create them. They are created and \n            maintained automatically by the SAS System.</p>\n            <p align=\"left\">This paper addresses a specific application of \n            dictionary tables - using them with the SQL macro interface. The \n            paper briefly reviews the different tables, then shows them at work \n            using a series of Real World examples. To emphasize just how very \n            cool and effective they are, we do some side-by-side comparisons of \n            code NOT utilizing the tables and code that does. The reader should \n            come away from this paper with: an understanding of the tables' \n            structure, an appreciation of their power, and a grasp of how to use \n            the techniques we demonstrate in the paper.</p>\n            <p align=\"left\"><i>Frank DiIorio is author of &quot;SAS Applications \n            Programming: A Gentle Introduction&quot; and (with Ken Hardy) &quot;Quick \n            Start to Data Analysis with SAS,&quot; Both titles are part of SAS \n            Institute's Books by Users series and have sold over 25,000 copies. \n            Frank has been active in the SouthEast SAS Users Group (SESUG) since \n            its inception, co-chairing the 1994 and 1996 conferences. He has, \n            much to his astonishment after doing the math, over a quarter \n            century experience with SAS software. His new book, &quot;The Elements of \n            SAS Programming Style,&quot; (working title) will be published &quot;real soon \n            now.&quot; When not writing *about* SAS, Frank writes *in* SAS, primarily \n            data management and reporting applications in the pharmaceutical \n            industry. A native New Yorker, he has lived in Chapel Hill, North \n            Carolina since 1974 and sort of buys into its claim of being the \n            &quot;Southern Part of Heaven.&quot;</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"left\"><span id=\"b\"></span><b>Summarization with Proc Means<br>\n            Ron Cody, UMDNJ</b></p>\n            <p align=\"left\">Several SAS procedures produce summary output data \n            sets. PROC MEANS (aka PROC SUMMARY) and PROC FREQ come to mind. This \n            talk will discuss how to produce and use these summary data sets. \n            Some of the version 8 additions to these procedures will be \n            discussed as well. For example, PROC MEANS now includes a CHARTYPE \n            option and a TYPES statement as well as an AUTONAME output option \n            (which automatically provides names to the various output \n            statistics). You may actually discover the mystery of the underscore \n            variables _TYPE_ and _FREQ_. So, come and learn some new neat stuff!</p>\n            <p align=\"left\"><i>Dr. Ron Cody is a Professor in the department of \n            Environmental and Community Medicine at the Robert Wood Johnson \n            Medical School, Piscataway, New Jersey. He has been a SAS user for \n            more than 20 years and is the author of &quot;Applied Statistics and the \n            SAS� Programming Language&quot; (fourth edition), published by Prentice \n            Hall. He has also authored or co-authored several books for the SAS \n            Institute as part of their Books by Users (BBU) series. Ron has \n            presented invited papers for numerous local, regional, and national \n            SAS conferences.</i></p>\n            <p align=\"left\">&nbsp;</p>\n            <p align=\"left\"><span id=\"c\"></span><b>SAS Drug Development<br>\n            Terry Druckman / SAS NJ office</b></p>\n            <p align=\"left\">The SAS Drug Development platform provides a \n            centralized repository of data and associated documents related to a \n            client-defined domain, such as compound or therapeutic area, and a \n            Web based framework through which this information can be managed \n            and accessed. The platform includes a knowledge management \n            infrastructure, framework to support collaboration, data warehousing \n            technologies and analysis and reporting. Through validation, audit \n            trails, security, etc., SDD can facilitate the obligation to readily \n            support government regulations such as 21 CFR Part 11 compliance. \n            The following link provides further information about the solution\n            <br>\n            <a href=\"http://www.sas.com/industry/pharma/drug_dev.html\">\n            www.sas.com/industry/pharma/drug_dev.html</a></p>\n              \n                \n            <p align=\"left\">&nbsp;</p>\n              \n                \n                  "
  },
  "meet2004.html": {
    "title": "Spring meeting - Tuesday, June 8, 2004, 9am",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n            <p></p>\n                          \n             \n                  <center>\n                  <b>Late \n                  Winter meeting - Friday, March 12, 2004, 9am</b></p>\n                  </center>\n                \n               \n                    <p style=\"text-align: left; font-weight: bold;\">\n                    <span id=\"a\"></span>Testing and \n                    Validating SAS Programs OR Beyond Debugging: Program \n                    Validation<br>\n                    Neil Howard / Ingenix Pharmaceutical Services</p>\n                    <p style=\"text-align: left;\">Powerpoint\n                    <a href=\"http://rvcc2.raritanval.edu/~bobberto/testing_validating.ppt\">\n                    presentation</a> from the meeting</p>\n                  \n                </div>\n                \n                \n                \n                \n                \"Act in haste and repent at \n                leisure; code too soon, and debug forever.\"\n                <span style=\"font-style: italic;\">Raymond Kennington</span></p>\n                \n                  <p>Overheard at an interview for a SAS programming position:&nbsp; \n                  \"But you don't have to test SAS programs!!!\"&nbsp; As the \n                  interviewers quickly escort the confused candidate out the \n                  door, they recall how often it is assumed that a fourth \n                  generation language \"does so much for you\" that you don't have \n                  to test the code.&nbsp; The SAS system is easy to use, and the \n                  learning curve to productivity is relatively short.&nbsp; But SAS \n                  is just as easy to ABUSE. Programmers and analysts must not \n                  lose sight of the indisputable facts: data is seldom clean, \n                  logic is too often faulty, and fingers walk clumsily over \n                  keyboards.&nbsp; Condition codes and clean logs are not accurate \n                  indicators of successful programs. </p>\n                  <p>Good debuggers make good programmers. And good analysts and \n                  problem-solvers make good programmers. And just because a SAS� \n                  program is free of errors, warnings, notes, and bugs does not \n                  guarantee that the program is doing what it is supposed to do. \n                  This paper addresses the process of debugging, testing and \n                  validating SAS programs and the tools available in the SAS \n                  language to facilitate the process.&nbsp; It covers techniques for \n                  ensuring that the logic and intent of the program is correct, \n                  that the requirements and design specifications are met, and \n                  that data errors are detected.&nbsp; Since as much as 80% of a \n                  programmer's time is invested in testing and validation, it's \n                  important to develop a personal approach to testing and a \n                  routine testing methodology in your group. </p>\n                  <p><i>Neil Howard is Manager of Statistical Programming at i3 \n                  Data Services in Basking Ridge, NJ; she was with Pfizer \n                  previously.&nbsp; A SAS user for more than twenty years, Neil has \n                  been an invited speaker since 1983 on such topics as: \n                  efficiency techniques, DATA step processing and internals, \n                  advanced DATA step techniques, testing and validation, \n                  graphics, effective presentations, and interviewing/hiring SAS \n                  programmers.&nbsp; She was a contract instructor for SAS Institute \n                  for seven years teaching fundamentals, programming, macro, \n                  report writing, graphics and the annotate facility.&nbsp; She has \n                  been a member of the SUGI Executive Committee since 1993 and \n                  was proud to chair SUGI 20 in Orlando.&nbsp; She is currently the \n                  Academic Chair for SESUG '04 to be held in Nashville in \n                  October 2004. </i> </p>\n                \n                \n                  <p>&nbsp;</p>\n                \n                \n                \n                    \n                      <p>\n                    <span id=\"b\"></span><b>ODS on SAS V9.1</b><br>\n                      <b>Sandy McNeil, SAS </b>(Eric Gebhart replaced Sandy for the \n                      talk )</p>\n                    \n               \n                \n                SAS 9.1 is out -- are you ready??&nbsp; \n                Take a quick trip with me through ODS-land to see what's new and \n                useful in the Output Delivery System.&nbsp;&nbsp; Some of the highlights \n                will be a discussion of two new destinations, MARKUP and \n                DOCUMENT, and how they can be useful to you.</p>\n                \n                \n            \n            \n              </p>\n            \n            \n              \n                \n                  <p><i>Eric has been with SAS since 1995. He is one of the \n                  original ODS developers and is responsible for HTML and the \n                  new MARKUP destination and Tagsets. </i> </p>\n                  <p><i>Sandy McNeill is the manager of the Output Delivery and \n                  Reporting department at SAS. The ODR department is responsible \n                  for ODS and the BASE reporting procedures -- Print, Tabulate, \n                  and Report.&nbsp; Sandy joined SAS in 1995 to support PROC REPORT, \n                  for which she is still the lead development support person.\n                  </i>\n                  </p>\n                  <p><i>Prior to joining SAS, Sandy worked at Square D where she \n                  wrote firmware for Programmable Logic Controllers, and then \n                  was the programming lead for the graphical user interface used \n                  to program the PLCs.&nbsp; Sandy's previous experience before \n                  Square D was six years with GTE Government Systems where she \n                  worked on the firmware for a communication device used by the \n                  Army during Operation Desert Storm.&nbsp; Sandy graduated Magna Cum \n                  Laude in 1985 with a B.S. in Computer Science from North \n                  Carolina State University.</i></p>\n                  <p>&nbsp;</p>\n            <p align=\"center\"><b>Spring \n            meeting - Tuesday, June 8, 2004, 9am</b></p>\n            <p>\n                    <span id=\"c\"></span>\n            <font style=\"font-size: 9pt\">\n            <b>Mrs. Clean Tackles Dirty Data</b></font><span style=\"font-size: 9pt\"><b>\n            </b>\n            <br>\n            </span><b><font style=\"font-size: 9pt\">Janet Stuelpner / Independent \n            Consultant</font><span style=\"font-size: 9pt\"> </span></b></p>\n            <p>What is clean data and how do you \n            clean it?&nbsp; This is an age-old question that has some pretty easy \n            answers.&nbsp; There are some techniques that can be used to find invalid \n            data values in both numeric and character data, missing values and \n            duplicate observations.&nbsp; Simple procedures and DATA steps can be \n            used to ferret out inappropriate observations.&nbsp; This presentation \n            will illustrate some of the techniques used after data entry is \n            complete and the data has to be reviewed and cleansed. </p>\n            <p><i>Janet Stuelpner provides programming \n            support in the areas of clinical trials, outcomes research and the \n            financial industry. She also provides both individual and group \n            technical training when needed at the client sites.&nbsp; Janet has \n            several degrees in the sciences. She has been a SAS user for 20 \n            years on many different platforms. Originally a systems programmer, \n            she has now turned her focus to applications programming and \n            teaching. She has been a presenter at users groups at all levels.</i></p>\n            <p>&nbsp;</p>\n            <p>\n            \n                    <span id=\"d\"></span>\n            \n              <b>The Input Statement: Where It's @<br>\n              Ron Cody / Professor, Robert Wood Johnson Medical School</b>\n            \n              &nbsp;</p>\n            </p>\n              The INPUT statement is one of the \n              most powerful and flexible features of SAS software.&nbsp; You can read \n              data values separated by spaces or commas (or other delimiters), \n              data values in specified columns, or data stored in a variety of \n              formats such as packed decimal, or binary.&nbsp; You can also read date \n              values in most of the standard formats. Along with an INFILE \n              statement, you can read data from external files as well.&nbsp; You can \n              place the data for several observations on a single data line or \n              you can read several lines of data and create a single \n              observation.&nbsp; Finally, you can read values from a line of data \n              and, depending on the value, decide how to read the remaining \n              data.&nbsp; This talk will tell you where it's @. \n            <p><i>Dr. Ron Cody is a Professor in the \n              department of Environmental and Community Medicine at the Robert \n              Wood Johnson Medical School, Piscataway, New Jersey.&nbsp; He has been \n              a SAS user since the late 70's&nbsp; and is the author of \"Applied \n              Statistics and the SAS� Programming Language\" (fourth edition), \n              published by Prentice Hall.&nbsp; He has also authored or co-authored \n              the following books for the SAS Institute as part of their Books \n              by Users series: SAS Functions by Example (just published), The \n              SAS Workbook, SAS Programming by Example, Cody's Data Cleaning \n              Techniques, and Longitudinal Data and SAS: A Programmer's Guide.&nbsp; \n              Ron has presented invited papers for numerous local, regional, and \n              national SAS conferences. </i></p>\n            <p>&nbsp;</p>\n            <p align=\"center\"><b>Early Autumn meeting - Friday, September 24, 2004, 9am\n            </b></p>\n              \n                \n                    <span id=\"e\"></span>\n              \n                \n                  <font size=\"+1\">\n                  <small><small><span style=\"font-size: 9pt\"><b>ODS:&nbsp; Step by \n                  Step<br>\n                  Wendi Wright, Educational Testing Service</b><br>\n                  </span></small><span style=\"font-size: 9pt\"><br>\n                  </span></small></font>The Output \n                  Delivery System (ODS) was developed by SAS� to create \n                  professional looking output reports, among other reasons. This \n                  paper introduces the beginning ODS user to the basic concepts \n                  of creating RTF and HTML files using SAS ODS on the MS Window \n                  platform. This paper is based on the same set of steps that I \n                  used when I was first learning ODS.<p><i>Wendi Wright has been working at \n                Education Testing Service since 1986. She has been using SAS for \n                almost that long and currently is responsible for teaching the \n                language to new hires in her department as well as using the \n                language for programming assignments.</i></p>\n            <p>&nbsp;</p>\n            <p>\n                    <span id=\"f\"></span>\n                  <span>PROC SQL - Is It a Required \n                  Tool of Good SAS�Programming? </span><br>\n                  <span>Dr. Ian Whitlock</span></p>\n            <p>\n                No one SAS tool can be the answer \n                to all problems. However, it should be hard to consider a SAS \n                programmer well versed in SAS, who does not use DATA steps. SQL \n                should be classified with the DATA step rather than procedures \n                because it is really a programming language in itself.<br>\n                <br>\n                In the past many good SAS programmers have resisted learning \n                PROC SQL on the basis that it is a database tool and that they \n                can get along without it. It is time (or past time) to \n                reconsider the question and change that belief.<br>\n                <br>\n                SQL has dramatically changed the nature of what good SAS macro \n                code looks like. It can simplify and standardize a number of \n                common SAS programming patterns involving combinations of the \n                DATA step, PROC SUMMARY, PROC SORT, and PROC PRINT.<br>\n                <br>\n                This tutorial will focus on problem examples with code where \n                PROC SQL has a distinct advantage in terms of code simplicity \n                over use of the more traditional SAS tools mentioned above. </p>\n            <p>\n                  <i>Dr. Ian Whitlock has been \n                programming largely in SAS since 1981 using an interactive \n                environment to develop programs for execution in a batch \n                environment. He is active on SAS-L, and has presented many \n                different papers at national, regional, and local SAS User Group \n                meetings.</i></p>\n            <p>\n                  &nbsp;</p>\n                \n                  <p align=\"center\">\n                \n                  <b>Late Autumn meeting - Friday, \n                10Dec2004, 9am</b></p>\n            <p>\n                \n                \n                \n                    <span id=\"g\"></span>\n                \n                \n                \n                  <span>SAS 9 and Business \n                  Intelligence<br>\n                    Terry Druckman, SAS, Bedminster, NJ</span><br>\n                  <br>\n                  This presentation will highlight some of the major V9 \n                  enhancements and focus on the Business Intelligence Tools<br>\n                  Product Demonstration will consist of the following:</p>\n                    <li>Enterprise Guide</li>\n                    <li>Stored Process Capability</li>\n                    <li>Web Report Studio</li>\n                    <li>Portal</li>\n                  \n                  <p><i>Terry is a presales Senior Systems Engineer in the Health and \n                  Life Sciences Division of SAS since the summer of 1997. He is \n                  based in Bedminster, New Jersey and supports the sales force \n                  across pharma, healthcare providers and healthcare insurers. \n                  He is currently focused on the Business Intelligence Tools \n                  that SAS offers much of which are new for SAS V9. <br>\n                  Prior to SAS, Terry worked for a small software development \n                  company that specialized in a 3rd and 4th generation Business \n                  Basic Language and various Accounting applications. He holds \n                  the BS degree from Villanova University and also has \n                  experience in the accounting field. </i> </p>\n                  \n                  <p>&nbsp;</p>\n                  <p>\n                    <span id=\"h\"></span>\n                  <span>%SYSFUNC; a powerful SAS \n                  tool<br>\n                    Foster Kerrison</span><br>\n                  <br>\n                  %SYSFUNC is a very powerful and flexible component of the SAS \n                  � system. This presentation is designed to teach you how to \n                  understand the basic elements of %SYSFUNC, and how to apply it \n                  to your daily tasks. You don't need to be a macro guru to use \n                  it. %SYSFUNC allows you to undertake a wide range of tasks \n                  related to your data by using consistent syntax. Understanding \n                  how to use %SYSFUNC is the key to success, and this \n                  presentation will teach you how.\n                  <a href=\"http://www.somerset-nj.com/njsug/fkpaper.html\">Paper</a><br>\n                  <br>\n                  <i>Foster Kerrison is a self taught SAS programmer. He is the \n                  founder, and first President, of the New Hampshire &amp; Vermont \n                  SAS users group. He is a strong believer in self help amongst \n                  SAS programmers, and is always interested in learning and \n                  teaching new ways to use SAS. A graduate of Harvard \n                  University, he is currently a masters student in Healthcare \n                  Informatics at the Royal College of Surgeons/University of \n                  Bath in the UK. He is a self employed contractor, who has \n                  worked in the Healthcare, Direct Marketing, and financial \n                  services industry, so he has a broad perspective on SAS \n                  applications. </i>\n              \n         \n            \n            <b>\n            <p>&nbsp;"
  },
  "meet2005.html": {
    "title": "Late Winter meeting - Friday, 04Mar2005, 9am",
    "content": "<p><font color=\"#000066\"><a href=\"/archive\">Archive of Past \n            Presentations</a></font></p>\n            \n            <p></p>\n                          \n              <p style=\"text-align: center; margin-left: 0px\">\n              <font color=\"#333300\"><b>Late \n              Winter meeting - Friday, 04Mar2005, 9am</b></p>\n              <b>\n              </center>\n           \n            \n            </b>\n           \n            \n              \n                <b>Take an In-Depth Look at the %EVAL Function <br>\n                </b>\n                <br>\n                <b>Beilei Xu, Merck &amp; Co., Inc., Rahway, NJ <br>\n                Lei Zhang, Merck &amp; Co., Inc., Rahway, NJ </b> \n                <br>\n                <br>\n                %EVAL is a widely used yet frequently misunderstood SAS(r) macro \n                language function due to its seemingly simple form. However, \n                when its actual argument is a complex macro expression \n                interlaced with special characters, mixed arithmetic and logical \n                operators, or macro quotation functions, its usage and result \n                become elusive and problematic. <br>\n                <br>\n                In this paper, we aim to explore and demystify the intricate \n                part of %EVAL. First, we explain the mechanism that the SAS \n                macro processor uses to invoke %EVAL, and point out the subtle \n                difference between the implicit and explicit uses of %EVAL \n                calls. Then, we reveal a series of hidden rules that %EVAL uses \n                to manipulate its actual macro argument embedded with different \n                types of special characters. Examples are provided to illustrate \n                those rules and exceptions on a case-by-case basis.\n            <p>\n                <i>Beilei Xu is a Sr. Statistical Programmer at Merck &amp; Co., Inc. \n                She has six years of SAS programming experience. <br>\n                <br>\n                Lei Zhang works as a senior statistical programmer at Merck &amp; \n                Co. Inc.. He is a SAS certified professional with 10+ years of \n                SAS programming experience. He has written several technical \n                papers for PharmaSUG, NESUG, and SUGI. His favorite topics are \n                advanced SAS macro programming, data manipulation with SQL and \n                Data/Proc steps, Java tools and SAS utilities for clinical study \n                analysis and reporting. </i> <br>\n                &nbsp;</p>\n            <p><br>\n                <b>A Guide to Understanding Web Application Development </b>\n                <br>\n                <br>\n                <b>Authors: Rob Girardin + Corey Benson <br>\n                Speaker: Scott Leslie, SAS Institute / Cary, NC. </b> <br>\n                <br>\n                You have been asked by your manager to port a legacy, fat-client \n                application to the web. There are so many directions you can \n                take in completing this project. It is hard to know where to \n                start and what technologies to use. The main focus of this paper \n                is to introduce you to server-side Java. We will answer \n                questions like: </p>\n                \n                  <li>What are the main benefits of using server-side Java \n                  technology? </li>\n                  <li>What are servlets, JavaServer Pages and custom tags? </li>\n                  <li>How do they all fit together? </li>\n                  <li>Why should you work Model 2 into your application design?\n                  </li>\n                  <li>How does the Struts framework enable you to control the \n                  flow of your application and component interactions? </li>\n                  <li>How do you customize the look of your web application \n                  using styles and templates? </li>\n                  <li>How do you deploy your web application? </li>\n                  <li>What are the pieces and parts? </li>\n                \n                <p>These topics will be covered while also highlighting how Version \n                3 of AppDev Studio makes it easier for you to build web \n                applications that are lightweight, easy to manage and instantly \n                connect to SAS software. <br>\n                \n                <br>\n                <i>Scott Leslie joined SAS Institute in 1994 in the Display \n                Products division developing parts of SAS/AF. He is an original \n                member of the AppDev Studio development team and serves as a \n                Software Manager for Java component development. His primary \n                areas of development have been JavaBeans and model components \n                which provide access to SAS data and services. He has a BS in \n                Mathematics from the University of North Carolina at Chapel \n                Hill. </i> </p>\n              \n            \n            <b>\n            <p>&nbsp;"
  }
} as const

export type LegacyArchiveSlug = keyof typeof legacyArchivePages
